                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <p style={{ display: 'flex', alignItems: 'center', gap: '4px', opacity: 0.7, fontSize: '14px', fontWeight: '600', margin: 0 }}>
                            <FaMapMarkerAlt size={12} /> Somewhere Nearby
                        </p>
                    </div>
