                                    whileTap={{ scale: 0.95 }}
                                    onClick={() => navigate('/chat')}
                                    style={{ padding: '16px', borderRadius: '16px', background: '#F8FAFC', color: '#0F172A', border: 'none', fontWeight: '700', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }}
                                >
                                    <FaHeart /> Start Conversing
                                </motion.button>
                                <button
                                    onClick={() => setIsMatchReveal(false)}
                                    style={{ padding: '12px', background: 'transparent', color: 'rgba(255,255,255,0.4)', border: 'none', fontWeight: '600', cursor: 'pointer' }}
                                >
                                    Continue Browsing
                                </button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default BlindDate;

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FaPaperPlane, FaArrowLeft, FaEllipsisV, FaCheckDouble, FaRobot, FaShieldAlt, FaLightbulb, FaExclamationTriangle, FaLock, FaUnlock, FaGift, FaVideo } from 'react-icons/fa';
import { AppTheme } from '../theme/AppTheme';
import { useNavigate } from 'react-router-dom';
import { messageService } from '../services/message.service';
import { aiService } from '../services/ai.service';
import { giftService } from '../services/gift.service';
import { matchService } from '../services/match.service';
import { websocketService } from '../services/websocket.service';
import { useToast } from '../context/ToastContext';
import { useAuth } from '../context/AuthContext';

const Chat = () => {
    const navigate = useNavigate();
    const { user: authUser } = useAuth();
    const { showToast } = useToast();
    const [messages, setMessages] = useState([]);
    const [newMessage, setNewMessage] = useState('');
    const [isTyping, setIsTyping] = useState(false);
    const [loading, setLoading] = useState(true);
    const [aiSuggestions, setAiSuggestions] = useState(["How was your weekend?", "Tell me more about your bio!", "Coffee this week?"]);
    const [showAiPanel, setShowAiPanel] = useState(false);
    const [securityAnalysis, setSecurityAnalysis] = useState(null);
    const [decryptedMessages, setDecryptedMessages] = useState(new Set());
    const [match, setMatch] = useState(null);
    const [revealProgress, setRevealProgress] = useState(0);
    const [particlesActive, setParticlesActive] = useState(false);
    const messagesEndRef = useRef(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        const fetchMatchDetails = async () => {
            try {
                const data = await matchService.getMatchDetails(1); // Assume match 1 for demo
                setMatch(data);
                if (data?.isBlindMatch) {
                    setRevealProgress(data.revealProgress || 0);
                }
            } catch (err) {
                console.error("Failed to fetch match details:", err);
            }
        };
        fetchMatchDetails();

        const fetchMessages = async () => {
            try {
                setLoading(true);
                const rawData = await messageService.getMessages(1);
                const data = Array.isArray(rawData) ? rawData : [];

                const messagesWithSafety = await Promise.all(data.map(async (msg) => {
                    if (!msg.isMe) {
                        try {
                            const safety = await aiService.checkMessageSafety(msg.text);
                            return { ...msg, safety };
                        } catch (e) {
                            return { ...msg, safety: { is_safe: true } };
                        }
                    }
                    return { ...msg, safety: { is_safe: true } };
                }));

                setMessages(messagesWithSafety);

                try {
                    const analysis = await aiService.analyzeConversationSecurity("conv_1", messagesWithSafety, "u1", "s1");
                    setSecurityAnalysis(analysis);
                } catch (_e) {
                    setSecurityAnalysis(null);
                }

            } catch (error) {
                console.error("Failed to fetch messages:", error);
                setMessages([]);
            } finally {
                setLoading(false);
            }
        };

        fetchMessages();

        // Connect WebSocket
        websocketService.connect(async (msg) => {
            // Handle incoming message
            const safety = await aiService.checkMessageSafety(msg.content || msg.text);
            const formattedMsg = {
                id: msg.id,
                text: msg.content || msg.text,
                isMe: msg.senderId === authUser?.id,
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                status: 'read',
                safety: safety
            };
            setMessages(prev => [...prev, formattedMsg]);
        });

        return () => {
            websocketService.disconnect();
        };
    }, []);

    useEffect(() => {
        scrollToBottom();
    }, [messages, isTyping]);

    const handleSend = async (textOverride) => {
        const textToSend = typeof textOverride === 'string' ? textOverride : newMessage;
        if (!textToSend.trim()) return;

        const originalText = textToSend;
        setNewMessage('');

        // WebSocket send
        const success = websocketService.sendMessage({
            matchId: 1, // Assume match 1 for demo
            content: originalText,
            senderId: authUser?.id,
            recipientId: 2 // Assume recipient 2 for demo
        });

        if (!success) {
            // Fallback to REST if WS fails
            await messageService.sendMessage(1, originalText);

            // Local UI update if REST
            const tempId = Math.random();
            const sentMsg = {
                id: tempId,
                text: originalText,
                isMe: true,
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
                status: 'sent',
                safety: { is_safe: true }
            };
            setMessages(prev => [...prev, sentMsg]);
        }

        // Logic for Blind Date Reveal Increment
        if (match?.isBlindMatch && revealProgress < 100) {
            const nextReveal = Math.min(100, revealProgress + 5);
            setRevealProgress(nextReveal);

            // Sync with backend
            matchService.updateRevealProgress(match.id, nextReveal);

            // Special effect for milestones
            if (nextReveal % 25 === 0) {
                setParticlesActive(true);
                setTimeout(() => setParticlesActive(false), 3000);
            }

            // Special toast for clarity milestones
            if (nextReveal === 50) showToast("Neural Clarity increased to 50%! 🌫️✨", "success");
            if (nextReveal === 100) showToast("Total Reveal! You can now see each other clearly. 😍", "success");
        }
    };

    const handleDecrypt = (id) => {
        setDecryptedMessages(prev => new Set([...prev, id]));
    };

    const handleReport = async (msgId) => {
        await messageService.reportMessage(msgId, "AI detected potential scam/harassment");
        showToast("Message reported. Our safety team will review it.", "info");
    };

    const handleAcceptGift = async (transactionId) => {
        try {
            await giftService.acceptGift(transactionId);
            showToast("Gift accepted! 🎁✨", "success");
            // Optionally refresh messages here or wait for WS
        } catch (err) {
            showToast("Failed to accept gift.", "error");
        }
    };

    return (
        <div style={{
            height: '100vh',
            background: AppTheme.colors.lightBackground,
            display: 'flex',
            flexDirection: 'column',
            color: AppTheme.colors.textPrimary,
            overflow: 'hidden'
        }}>
            {/* Header */}
            <div style={{
                padding: '16px',
                background: '#FFFFFF',
                backdropFilter: 'blur(10px)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                borderBottom: '1px solid #E5E7EB',
                zIndex: 10,
                boxShadow: '0 2px 10px rgba(0,0,0,0.02)'
            }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <motion.button
                        whileTap={{ scale: 0.9 }}
                        onClick={() => navigate(-1)}
                        style={{ background: 'none', border: 'none', color: AppTheme.colors.textPrimary, cursor: 'pointer', padding: '4px' }}
                    >
                        <FaArrowLeft size={20} />
                    </motion.button>

                    <div style={{ position: 'relative' }}>
                        <div style={{
                            width: '40px', height: '40px', borderRadius: '50%',
                            background: '#ccc', overflow: 'hidden',
                            boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
                        }}>
                            <img
                                src={match?.avatar || "https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100"}
                                alt="Avatar"
                                style={{
                                    width: '100%', height: '100%', objectFit: 'cover',
                                    filter: match?.isBlindMatch ? `blur(${(100 - revealProgress) / 10}px)` : 'none',
                                    transition: 'filter 1s ease'
                                }}
                            />
                        </div>
                        {match?.online && (
                            <span style={{
                                position: 'absolute', bottom: 0, right: 0,
                                width: '12px', height: '12px',
                                borderRadius: '50%', background: AppTheme.colors.successGreen,
                                border: '2px solid #FFFFFF'
                            }} />
                        )}
                    </div>

                    <div>
                        <h3 style={{ fontSize: '16px', fontWeight: '700', margin: 0, display: 'flex', alignItems: 'center', gap: '6px' }}>
                            {match?.isBlindMatch && revealProgress < 100 ? "Mystery Match" : (match?.name || "Sarah")}
                            {match?.isBlindMatch && (
                                <span style={{ fontSize: '10px', background: '#1e1b4b', color: '#fff', padding: '1px 6px', borderRadius: '8px', fontWeight: '800' }}>BLIND</span>
                            )}
                        </h3>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                            {match?.isBlindMatch ? (
                                <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                                    <div style={{ width: '60px', height: '4px', background: '#E5E7EB', borderRadius: '2px', overflow: 'hidden' }}>
                                        <motion.div
                                            initial={{ width: 0 }}
                                            animate={{ width: `${revealProgress}%` }}
                                            style={{ height: '100%', background: AppTheme.gradients.primary }}
                                        />
                                    </div>
                                    <span style={{ fontSize: '10px', color: AppTheme.colors.primaryPink, fontWeight: '800' }}>{revealProgress}% Clarified</span>
                                </div>
                            ) : (
                                <>
                                    <FaShieldAlt size={12} color={securityAnalysis?.is_safe ? AppTheme.colors.successGreen : AppTheme.colors.primaryPink} />
                                    <span style={{ fontSize: '12px', color: AppTheme.colors.textTertiary, fontWeight: '500' }}>
                                        {securityAnalysis ? `Safety Score: ${securityAnalysis.overall_safety_score}%` : "Analyzing Safety..."}
                                    </span>
                                </>
                            )}
                        </div>
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
                    <motion.div
                        whileTap={{ scale: 0.9 }}
                        onClick={() => navigate('/gifts')}
                        style={{ color: AppTheme.colors.primaryPink, cursor: 'pointer' }}
                    >
                        <FaGift size={22} title="Send a Gift" />
                    </motion.div>
                    <motion.div
                        whileTap={{ scale: 0.9 }}
                        onClick={() => navigate('/video-call', { state: { matchName: "Sarah", matchImage: "https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=600" } })}
                        style={{ color: AppTheme.colors.brandBlue, cursor: 'pointer' }}
                    >
                        <FaVideo size={22} title="Video Call" />
                    </motion.div>
                    <motion.div
                        whileTap={{ scale: 0.9 }}
                        onClick={() => setShowAiPanel(!showAiPanel)}
                        style={{ color: showAiPanel ? AppTheme.colors.primaryPink : AppTheme.colors.textSecondary, cursor: 'pointer' }}
                    >
                        <FaRobot size={22} title="AI Security Center" />
                    </motion.div>
                    <FaEllipsisV style={{ color: AppTheme.colors.textTertiary, cursor: 'pointer' }} />
                </div>
            </div>

            {/* AI Security Panel */}
            <AnimatePresence>
                {showAiPanel && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        style={{ background: '#FFFFFF', borderBottom: '1px solid #E5E7EB', overflow: 'hidden', boxShadow: '0 4px 12px rgba(0,0,0,0.05)' }}
                    >
                        <div style={{ padding: '20px' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '15px' }}>
                                <FaShieldAlt color={AppTheme.colors.primaryPink} size={20} />
                                <h4 style={{ margin: 0, fontSize: '16px', fontWeight: '700', color: AppTheme.colors.textPrimary }}>Neural Security Audit</h4>
                            </div>

                            {securityAnalysis?.warnings?.length > 0 ? (
                                <div style={{ background: 'rgba(255, 68, 68, 0.05)', border: '1px solid rgba(255, 68, 68, 0.2)', borderRadius: '12px', padding: '12px', marginBottom: '15px' }}>
                                    {securityAnalysis.warnings.map((w, idx) => (
                                        <p key={idx} style={{ color: '#E02424', fontSize: '14px', margin: '4px 0', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: '500' }}>
                                            <FaExclamationTriangle size={14} /> {w}
                                        </p>
                                    ))}
                                </div>
                            ) : (
                                <p style={{ fontSize: '14px', color: AppTheme.colors.successGreen, marginBottom: '15px', fontWeight: '500' }}>
                                    ✔ No immediate threats detected in this conversation.
                                </p>
                            )}

                            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                                <h5 style={{ margin: 0, fontSize: '12px', color: AppTheme.colors.textSecondary, textTransform: 'uppercase', fontWeight: '700' }}>AI Recommendations</h5>
                                {securityAnalysis?.recommendations?.map((rec, i) => (
                                    <div key={i} style={{ fontSize: '14px', display: 'flex', alignItems: 'center', gap: '8px', color: AppTheme.colors.textPrimary }}>
                                        <FaLightbulb size={14} color="#FBBF24" /> {rec}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Messages */}
            <div style={{ flex: 1, padding: '16px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {messages.map((msg) => {
                    const isUnsafe = msg.safety && !msg.safety.is_safe;
                    const isDecrypted = decryptedMessages.has(msg.id);

                    return (
                        <motion.div
                            key={msg.id}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            style={{
                                alignSelf: msg.isMe ? 'flex-end' : 'flex-start',
                                maxWidth: '75%',
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: msg.isMe ? 'flex-end' : 'flex-start'
                            }}
                        >
                            <div style={{
                                padding: '12px 16px',
                                borderRadius: '20px',
                                borderBottomRightRadius: msg.isMe ? '4px' : '20px',
                                borderBottomLeftRadius: msg.isMe ? '20px' : '4px',
                                background: msg.isMe ? AppTheme.gradients.primary : '#FFFFFF',
                                border: isUnsafe && !isDecrypted ? '1px solid #EF4444' : (msg.isMe ? 'none' : '1px solid #E5E7EB'),
                                boxShadow: msg.isMe ? '0 4px 10px rgba(253, 41, 123, 0.2)' : '0 2px 5px rgba(0,0,0,0.02)',
                                color: msg.isMe ? '#FFFFFF' : AppTheme.colors.textPrimary,
                                position: 'relative'
                            }}>
                                {msg.messageType === 'GIFT' ? (
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                                            <div style={{ width: '40px', height: '40px', background: 'rgba(255,255,255,0.2)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '20px' }}>
                                                🎁
                                            </div>
                                            <div>
                                                <span style={{ fontWeight: '800', fontSize: '14px', display: 'block' }}>New Gift Received!</span>
                                                <p style={{ fontSize: '15px', margin: 0, opacity: 0.9 }}>{msg.text}</p>
                                            </div>
                                        </div>
                                        {!msg.isMe && (
                                            <button
                                                onClick={() => handleAcceptGift(msg.referenceId)}
                                                style={{
                                                    background: '#fff', color: AppTheme.colors.primaryPink,
                                                    border: 'none', padding: '8px 16px', borderRadius: '12px',
                                                    fontSize: '13px', fontWeight: '800', cursor: 'pointer',
                                                    boxShadow: '0 4px 10px rgba(0,0,0,0.1)'
                                                }}
                                            >
                                                Accept Gift
                                            </button>
                                        )}
                                    </div>
                                ) : msg.messageType === 'SYSTEM' ? (
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', opacity: 0.8 }}>
                                        <FaCheckDouble size={14} />
                                        <p style={{ fontSize: '14px', fontStyle: 'italic', margin: 0 }}>{msg.text}</p>
                                    </div>
                                ) : isUnsafe && !isDecrypted ? (
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#EF4444' }}>
                                            <FaLock size={14} />
                                            <span style={{ fontSize: '14px', fontWeight: '700' }}>Potentially Unsafe Content</span>
                                        </div>
                                        <p style={{ fontSize: '15px', margin: 0, filter: 'blur(5px)', userSelect: 'none' }}>
                                            {msg.text}
                                        </p>
                                        <div style={{ display: 'flex', gap: '8px', marginTop: '8px' }}>
                                            <button
                                                onClick={() => handleDecrypt(msg.id)}
                                                style={{ background: '#F3F4F6', border: 'none', color: AppTheme.colors.textPrimary, padding: '8px 12px', borderRadius: '12px', fontSize: '12px', fontWeight: '600', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px', transition: 'background 0.2s' }}
                                            >
                                                <FaUnlock size={10} /> Reveal
                                            </button>
                                            <button
                                                onClick={() => handleReport(msg.id)}
                                                style={{ background: '#FEF2F2', border: '1px solid #FECACA', color: '#EF4444', padding: '8px 12px', borderRadius: '12px', fontSize: '12px', fontWeight: '600', cursor: 'pointer', transition: 'background 0.2s' }}
                                            >
                                                Report
                                            </button>
                                        </div>
                                    </div>
                                ) : (
                                    <>
                                        <p style={{ fontSize: '15px', lineHeight: '1.5', margin: 0 }}>{msg.text}</p>
                                        {isUnsafe && isDecrypted && (
                                            <div style={{ marginTop: '8px', padding: '6px 10px', background: '#FEF2F2', border: '1px solid #FECACA', borderRadius: '8px', fontSize: '11px', color: '#EF4444', display: 'flex', alignItems: 'center', gap: '6px', fontWeight: '500' }}>
                                                <FaExclamationTriangle size={10} /> AI Warning: {msg.safety.reasons?.join(', ')}
                                            </div>
                                        )}
                                    </>
                                )}
                            </div>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '4px', marginTop: '6px', paddingRight: '4px' }}>
                                <span style={{ fontSize: '11px', color: AppTheme.colors.textTertiary, fontWeight: '500' }}>{msg.time}</span>
                                {msg.isMe && (
                                    <FaCheckDouble size={12} color={msg.status === 'read' ? AppTheme.colors.brandBlue : AppTheme.colors.textTertiary} />
                                )}
                            </div>
                        </motion.div>
                    );
                })}

                {isTyping && (
                    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ alignSelf: 'flex-start', marginLeft: '8px' }}>
                        <div style={{
                            background: '#FFFFFF', padding: '14px 16px',
                            borderRadius: '20px', borderBottomLeftRadius: '4px',
                            border: '1px solid #E5E7EB',
                            display: 'flex', gap: '6px',
                            boxShadow: '0 2px 5px rgba(0,0,0,0.02)'
                        }}>
                            <motion.div animate={{ y: [0, -5, 0] }} transition={{ repeat: Infinity, duration: 0.6 }} style={{ width: 8, height: 8, background: AppTheme.colors.textTertiary, borderRadius: '50%' }} />
                            <motion.div animate={{ y: [0, -5, 0] }} transition={{ repeat: Infinity, duration: 0.6, delay: 0.2 }} style={{ width: 8, height: 8, background: AppTheme.colors.textTertiary, borderRadius: '50%' }} />
                            <motion.div animate={{ y: [0, -5, 0] }} transition={{ repeat: Infinity, duration: 0.6, delay: 0.4 }} style={{ width: 8, height: 8, background: AppTheme.colors.textTertiary, borderRadius: '50%' }} />
                        </div>
                    </motion.div>
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Smart Suggestions Chips */}
            <div style={{ padding: '0 16px', display: 'flex', gap: '8px', overflowX: 'auto', paddingBottom: '12px', scrollbarWidth: 'none' }}>
                {aiSuggestions.map((text, i) => (
                    <motion.button
                        key={i}
                        whileTap={{ scale: 0.95 }}
                        onClick={() => handleSend(text)}
                        style={{
                            background: '#FFFFFF',
                            border: '1px solid #E5E7EB',
                            color: AppTheme.colors.textPrimary,
                            padding: '10px 16px',
                            borderRadius: '20px',
                            fontSize: '14px',
                            fontWeight: '500',
                            whiteSpace: 'nowrap',
                            cursor: 'pointer',
                            boxShadow: '0 2px 5px rgba(0,0,0,0.02)',
                            transition: 'background 0.2s'
                        }}
                    >
                        {text}
                    </motion.button>
                ))}
            </div>

            {/* Input Area */}
            <div style={{ padding: '16px', paddingBottom: '32px', background: '#FFFFFF', borderTop: '1px solid #E5E7EB' }}>
                <form
                    onSubmit={(e) => { e.preventDefault(); handleSend(); }}
                    style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: '12px',
                        background: '#F9FAFB',
                        padding: '12px 16px',
                        borderRadius: '24px',
                        border: `1px solid #E5E7EB`
                    }}
                >
                    <input
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        placeholder="Type a message..."
                        style={{
                            background: 'transparent',
                            border: 'none',
                            color: AppTheme.colors.textPrimary,
                            flex: 1,
                            outline: 'none',
                            fontSize: '15px'
                        }}
                    />
                    <motion.button
                        whileTap={{ scale: 0.9 }}
                        type="submit"
                        disabled={!newMessage.trim()}
                        style={{
                            background: 'transparent',
                            border: 'none',
                            color: newMessage.trim() ? AppTheme.colors.primaryPink : AppTheme.colors.textTertiary,
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            opacity: newMessage.trim() ? 1 : 0.5,
                            transition: 'color 0.2s'
                        }}
                    >
                        <FaPaperPlane size={22} />
                    </motion.button>
                </form>
            </div>
            {particlesActive && <FloatingParticles count={20} />}
        </div>
    );
};

const seededRandom = (seed) => {
    const x = Math.sin(seed) * 10000;
    return x - Math.floor(x);
};

const FloatingParticles = ({ count }) => (
    <div style={{ position: 'fixed', inset: 0, pointerEvents: 'none', zIndex: 9999 }}>
        {[...Array(count)].map((_, i) => (
            <motion.div
                key={i}
                initial={{
                    opacity: 0,
                    x: seededRandom(i + 1) * window.innerWidth,
                    y: window.innerHeight + 100,
                    scale: seededRandom(i + 2) * 0.5 + 0.5
                }}
                animate={{
                    opacity: [0, 1, 0.5, 0],
                    y: -100,
                    x: seededRandom(i + 3) * window.innerWidth,
                    rotate: seededRandom(i + 4) * 360
                }}
                transition={{
                    duration: seededRandom(i + 5) * 3 + 2,
                    ease: "easeOut",
                    repeat: Infinity,
                    delay: seededRandom(i + 6) * 2
                }}
                style={{
                    position: 'absolute',
                    fontSize: `${seededRandom(i + 7) * 30 + 10}px`,
                    filter: 'drop-shadow(0 0 10px rgba(253, 41, 123, 0.5))'
                }}
            >
                {['💖', '✨', '💎', '🌸', '🎁', '🔥'][Math.floor(seededRandom(i + 8) * 6)]}
            </motion.div>
        ))}
    </div>
);

export default Chat;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FaGift, FaSearch, FaHeart, FaTimes, FaCheck, FaTruck, FaUserFriends, FaArrowLeft } from 'react-icons/fa';
import GlassCard from '../components/common/GlassCard';
import { AppTheme } from '../theme/AppTheme';
import PremiumButton from '../components/common/PremiumButton';
import { giftService } from '../services/gift.service';
import { matchService } from '../services/match.service';
import { useNavigate } from 'react-router-dom';
import { useToast } from '../context/ToastContext';

const GIFT_CATEGORIES = ['All', 'Flowers', 'Chocolates', 'Teddy', 'Jewelry', 'Virtual'];

const Gifts = () => {
    const navigate = useNavigate();
    const { showToast } = useToast();
    const [gifts, setGifts] = useState([]);
    const [upcomingGifts, setUpcomingGifts] = useState([]);
    const [receivedGifts, setReceivedGifts] = useState([]);
    const [matches, setMatches] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedCategory, setSelectedCategory] = useState('All');
    const [activeTab, setActiveTab] = useState('Catalog');

    // Send Flow State
    const [isSelectingMatch, setIsSelectingMatch] = useState(false);
    const [selectedGift, setSelectedGift] = useState(null);
    const [sending, setSending] = useState(false);

    useEffect(() => {
        const fetchData = async () => {
            try {
                setLoading(true);
                const [catalogData, upcomingData, receivedData, matchData] = await Promise.all([
                    giftService.getCatalog(),
                    giftService.getUpcomingGifts(),
                    giftService.getReceivedGifts(),
                    matchService.getMatches()
                ]);
                setGifts(Array.isArray(catalogData) ? catalogData : []);
                setUpcomingGifts(Array.isArray(upcomingData) ? upcomingData : []);
                setReceivedGifts(Array.isArray(receivedData) ? receivedData : []);
                setMatches(Array.isArray(matchData) ? matchData : []);
            } catch (error) {
                console.error("Failed to fetch gifts data:", error);
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    const handleSendGift = (gift) => {
        setSelectedGift(gift);
        setIsSelectingMatch(true);
    };

    const confirmSend = async (matchId) => {
        setSending(true);
        await giftService.sendGift(matchId, selectedGift.id);
        setSending(false);
        setIsSelectingMatch(false);
        setSelectedGift(null);
        showToast("Gift sent successfully!", "success");
    };

    const handleAcceptReceived = async (giftId) => {
        await giftService.acceptGift(giftId);
        showToast("Gift accepted! Check your wallet/inventory.", "success");
        setReceivedGifts(prev => prev.map(g => g.id === giftId ? { ...g, status: 'accepted' } : g));
    };

    const handleDeclineReceived = async (giftId) => {
        await giftService.cancelGift(giftId);
        showToast("Gift declined.", "info");
        setReceivedGifts(prev => prev.filter(g => g.id !== giftId));
    };

    const filteredGifts = selectedCategory === 'All'
        ? gifts
        : gifts.filter(g => g.category === selectedCategory);


    return (
        <div style={{
            minHeight: '100vh',
            background: AppTheme.colors.lightBackground,
            padding: '24px',
            paddingBottom: '120px',
            color: AppTheme.colors.textPrimary,
            position: 'relative',
            overflowX: 'hidden'
        }}>
            <header style={{ marginBottom: '32px', position: 'relative', zIndex: 10 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '24px' }}>
                    <motion.button
                        whileTap={{ scale: 0.9 }}
                        onClick={() => navigate(-1)}
                        style={{ width: '40px', height: '40px', borderRadius: '50%', background: '#FFFFFF', boxShadow: '0 2px 10px rgba(0,0,0,0.05)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: AppTheme.colors.textPrimary, border: 'none', cursor: 'pointer' }}
                    >
                        <FaArrowLeft size={16} />
                    </motion.button>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: '16px' }}>
                    <div>
                        <h1 style={{ fontSize: '32px', margin: 0, fontWeight: '800', letterSpacing: '-0.5px', color: AppTheme.colors.textPrimary }}>Gifts</h1>
                        <p style={{ color: AppTheme.colors.textSecondary, fontSize: '15px', fontWeight: '500', marginTop: '4px' }}>Send & Receive Tokens of Affection</p>
                    </div>
                    <div style={{
                        display: 'flex', background: '#FFFFFF',
                        borderRadius: '20px', padding: '4px', border: '1px solid #E5E7EB',
                        boxShadow: '0 2px 10px rgba(0,0,0,0.02)'
                    }}>
                        {['Catalog', 'Sent', 'Received'].map(tab => (
                            <button
                                key={tab}
                                onClick={() => setActiveTab(tab)}
                                style={{
                                    padding: '8px 16px', borderRadius: '14px', border: 'none',
                                    background: activeTab === tab ? AppTheme.gradients.primary : 'transparent',
                                    color: activeTab === tab ? '#FFFFFF' : AppTheme.colors.textSecondary,
                                    fontSize: '13px', fontWeight: '700', cursor: 'pointer', transition: 'all 0.3s'
                                }}
                            >
                                {tab}
                                {tab === 'Received' && receivedGifts.filter(g => g.status === 'pending').length > 0 && (
                                    <span style={{ marginLeft: '4px', background: '#FFFFFF', color: AppTheme.colors.primaryPink, borderRadius: '50%', padding: '2px 6px', fontSize: '10px' }}>
                                        {receivedGifts.filter(g => g.status === 'pending').length}
                                    </span>
                                )}
                            </button>
                        ))}
                    </div>
                </div>
            </header>

            {activeTab === 'Catalog' && (
                <>
                    {/* Categories Scroller */}
                    <div style={{ display: 'flex', overflowX: 'auto', gap: '12px', paddingBottom: '24px', scrollbarWidth: 'none', position: 'relative', zIndex: 10 }}>
                        {GIFT_CATEGORIES.map(cat => (
                            <motion.button
                                key={cat}
                                whileTap={{ scale: 0.95 }}
                                onClick={() => setSelectedCategory(cat)}
                                style={{
                                    padding: '12px 24px', borderRadius: '20px', border: selectedCategory === cat ? 'none' : '1px solid #E5E7EB',
                                    background: selectedCategory === cat ? AppTheme.colors.primaryPink : '#FFFFFF',
                                    color: selectedCategory === cat ? '#fff' : AppTheme.colors.textSecondary,
                                    whiteSpace: 'nowrap', cursor: 'pointer', fontSize: '14px', fontWeight: '600',
                                    transition: 'all 0.2s', boxShadow: selectedCategory === cat ? '0 4px 10px rgba(253, 41, 123, 0.2)' : '0 2px 5px rgba(0,0,0,0.02)'
                                }}
                            >
                                {cat}
                            </motion.button>
                        ))}
                    </div>

                    <motion.div
                        layout
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))', gap: '20px', position: 'relative', zIndex: 10 }}
                    >
                        {filteredGifts.map((gift, i) => (
                            <motion.div layout key={gift.id} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: i * 0.05 }} >
                                <div style={{ padding: '24px', display: 'flex', flexDirection: 'column', alignItems: 'center', background: '#FFFFFF', borderRadius: '24px', border: '1px solid #E5E7EB', boxShadow: '0 4px 15px rgba(0,0,0,0.02)' }}>
                                    <motion.div whileHover={{ scale: 1.1, rotate: 5 }} style={{ width: '90px', height: '90px', borderRadius: '24px', background: '#F9FAFB', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '44px', marginBottom: '20px' }}>
                                        {gift.image}
                                    </motion.div>
                                    <h3 style={{ fontSize: '16px', fontWeight: '800', textAlign: 'center', marginBottom: '8px', color: AppTheme.colors.textPrimary }}>{gift.name}</h3>
                                    <span style={{ color: AppTheme.colors.primaryPink, fontWeight: '800', fontSize: '18px', marginBottom: '16px' }}>₹{gift.price}</span>
                                    <PremiumButton text="Send Gift" type="gradient" fullWidth onClick={() => handleSendGift(gift)} style={{ height: '44px', borderRadius: '16px' }} />
                                </div>
                            </motion.div>
                        ))}
                    </motion.div>
                </>
            )}

            {activeTab === 'Sent' && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                    {upcomingGifts.length === 0 ? (
                        <EmptyGifts message="Your sent gifts history will appear here." />
                    ) : (
                        upcomingGifts.map((gift, i) => <SentGiftCard key={gift.id} gift={gift} index={i} />)
                    )}
                </motion.div>
            )}

            {activeTab === 'Received' && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                    {receivedGifts.length === 0 ? (
                        <EmptyGifts message="No gifts received yet." />
                    ) : (
                        receivedGifts.map((gift, i) => (
                            <ReceivedGiftCard
                                key={gift.id}
                                gift={gift}
                                index={i}
                                onAccept={() => handleAcceptReceived(gift.id)}
                                onDecline={() => handleDeclineReceived(gift.id)}
                            />
                        ))
                    )}
                </motion.div>
            )}

            {/* Premium Match Selection Overlay */}
            <AnimatePresence>
                {isSelectingMatch && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        style={{
                            position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)',
                            backdropFilter: 'blur(8px)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px'
                        }}
                    >
                        <motion.div
                            initial={{ scale: 0.95, y: 20 }}
                            animate={{ scale: 1, y: 0 }}
                            exit={{ scale: 0.95, y: 20 }}
                            style={{ width: '100%', maxWidth: '400px' }}
                        >
                            <div style={{ padding: '32px', position: 'relative', borderRadius: '32px', border: '1px solid #E5E7EB', background: '#FFFFFF', boxShadow: '0 20px 40px rgba(0,0,0,0.1)' }}>
                                <motion.button
                                    whileTap={{ scale: 0.9 }}
                                    onClick={() => setIsSelectingMatch(false)}
                                    style={{ position: 'absolute', top: '24px', right: '24px', background: '#F3F4F6', border: 'none', color: AppTheme.colors.textSecondary, cursor: 'pointer', width: '36px', height: '36px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                                >
                                    <FaTimes size={16} />
                                </motion.button>

                                <div style={{ textAlign: 'center', marginBottom: '32px' }}>
                                    <div style={{ fontSize: '48px', marginBottom: '16px' }}>{selectedGift?.image}</div>
                                    <h3 style={{ fontSize: '24px', fontWeight: '800', margin: 0, color: AppTheme.colors.textPrimary }}>Select Recipient</h3>
                                    <p style={{ color: AppTheme.colors.textSecondary, fontSize: '15px', marginTop: '8px' }}>Who should receive this {selectedGift?.name}?</p>
                                </div>

                                <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', maxHeight: '350px', overflowY: 'auto', paddingRight: '4px' }}>
                                    {matches.map(match => (
                                        <motion.div
                                            key={match.id}
                                            whileTap={{ scale: 0.98 }}
                                            onClick={() => confirmSend(match.id)}
                                            style={{
                                                display: 'flex', alignItems: 'center', gap: '16px', padding: '16px',
                                                background: '#F9FAFB', borderRadius: '20px', cursor: 'pointer',
                                                border: '1px solid #E5E7EB', transition: 'all 0.2s',
                                                boxShadow: '0 2px 5px rgba(0,0,0,0.02)'
                                            }}
                                        >
                                            <div style={{ position: 'relative' }}>
                                                <img src={match.avatar} style={{ width: '48px', height: '48px', borderRadius: '50%', objectFit: 'cover' }} alt="" />
                                                <div style={{ position: 'absolute', bottom: '0', right: '0', width: '14px', height: '14px', background: AppTheme.colors.successGreen, borderRadius: '50%', border: '2px solid #FFFFFF' }} />
                                            </div>
                                            <div style={{ flex: 1 }}>
                                                <span style={{ display: 'block', fontWeight: '700', fontSize: '16px', color: AppTheme.colors.textPrimary }}>{match.name}</span>
                                            </div>
                                            <div style={{ width: '36px', height: '36px', borderRadius: '50%', background: `${AppTheme.colors.primaryPink}15`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                                <FaHeart color={AppTheme.colors.primaryPink} size={14} />
                                            </div>
                                        </motion.div>
                                    ))}
                                    {matches.length === 0 && !loading && (
                                        <p style={{ textAlign: 'center', color: AppTheme.colors.textSecondary, fontSize: '15px' }}>No matches yet to send a gift to.</p>
                                    )}
                                </div>
                                {sending && (
                                    <div style={{ position: 'absolute', inset: 0, background: 'rgba(255,255,255,0.7)', borderRadius: '32px', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 10 }}>
                                        <motion.div animate={{ rotate: 360 }} transition={{ repeat: Infinity, duration: 1, ease: 'linear' }} style={{ width: '40px', height: '40px', border: `4px solid ${AppTheme.colors.primaryPink}`, borderTopColor: 'transparent', borderRadius: '50%' }} />
                                    </div>
                                )}
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>

            <AnimatePresence>
                {sending && <FloatingParticles count={15} />}
            </AnimatePresence>
        </div>
    );
};

const seededRandom = (seed) => {
    const x = Math.sin(seed) * 10000;
    return x - Math.floor(x);
};

const FloatingParticles = ({ count }) => (
    <div style={{ position: 'fixed', inset: 0, pointerEvents: 'none', zIndex: 9999 }}>
        {[...Array(count)].map((_, i) => (
            <motion.div
                key={i}
                initial={{
                    opacity: 0,
                    x: seededRandom(i + 1) * window.innerWidth,
                    y: window.innerHeight + 100,
                    scale: seededRandom(i + 2) * 0.5 + 0.5
                }}
                animate={{
                    opacity: [0, 1, 0.5, 0],
                    y: -100,
                    x: seededRandom(i + 3) * window.innerWidth,
                    rotate: seededRandom(i + 4) * 360
                }}
                transition={{
                    duration: seededRandom(i + 5) * 3 + 2,
                    ease: "easeOut",
                    repeat: Infinity,
                    delay: seededRandom(i + 6) * 2
                }}
                style={{
                    position: 'absolute',
                    fontSize: `${seededRandom(i + 7) * 30 + 10}px`,
                    filter: 'drop-shadow(0 0 10px rgba(253, 41, 123, 0.5))'
                }}
            >
                {['💖', '✨', '💎', '🌸', '🎁'][Math.floor(seededRandom(i + 8) * 5)]}
            </motion.div>
        ))}
    </div>
);

const EmptyGifts = ({ message }) => (
    <div style={{ textAlign: 'center', padding: '60px 40px', background: '#FFFFFF', borderRadius: '32px', border: '1px solid #E5E7EB' }}>
        <FaGift size={40} color={AppTheme.colors.textTertiary} style={{ marginBottom: '16px' }} />
        <h3 style={{ fontSize: '20px', fontWeight: '800', marginBottom: '8px', color: AppTheme.colors.textPrimary }}>No Gifts</h3>
        <p style={{ color: AppTheme.colors.textSecondary, fontSize: '15px' }}>{message}</p>
    </div>
);

const SentGiftCard = ({ gift, index }) => (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: index * 0.1 }}>
        <div style={{ padding: '20px', display: 'flex', alignItems: 'center', gap: '20px', borderRadius: '24px', border: '1px solid #E5E7EB', background: '#FFFFFF', boxShadow: '0 2px 10px rgba(0,0,0,0.02)' }}>
            <div style={{ fontSize: '32px', background: '#F9FAFB', width: '64px', height: '64px', borderRadius: '16px', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 10px rgba(0,0,0,0.05)', border: '1px solid #F3F4F6' }}>
                {gift.image}
            </div>
            <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4px' }}>
                    <h4 style={{ margin: 0, fontSize: '16px', fontWeight: '800', color: AppTheme.colors.textPrimary }}>{gift.name}</h4>
                    <span style={{ fontSize: '11px', padding: '4px 10px', borderRadius: '10px', background: `${AppTheme.colors.primaryPink}15`, color: AppTheme.colors.primaryPink, fontWeight: '800' }}>{gift.status}</span>
                </div>
                <p style={{ margin: '0', fontSize: '14px', color: AppTheme.colors.textSecondary }}>Sent to <span style={{ color: AppTheme.colors.textPrimary, fontWeight: '700' }}>{gift.matchName}</span></p>
                <div style={{ marginTop: '8px', display: 'flex', alignItems: 'center', gap: '6px', color: AppTheme.colors.textTertiary, fontSize: '13px' }}>
                    <FaTruck size={14} /> <span>Est. Delivery: {gift.deliveryDate}</span>
                </div>
            </div>
        </div>
    </motion.div>
);

const ReceivedGiftCard = ({ gift, index, onAccept, onDecline }) => (
    <motion.div initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: index * 0.1 }}>
        <div style={{ padding: '20px', borderRadius: '24px', border: '1px solid #E5E7EB', background: '#FFFFFF', boxShadow: '0 4px 20px rgba(0,0,0,0.03)' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '20px', marginBottom: gift.status === 'pending' ? '20px' : '0' }}>
                <div style={{ fontSize: '40px', background: AppTheme.gradients.primary, width: '70px', height: '70px', borderRadius: '20px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', boxShadow: AppTheme.shadows.glow }}>
                    {gift.image}
                </div>
                <div style={{ flex: 1 }}>
                    <h4 style={{ margin: 0, fontSize: '18px', fontWeight: '800', color: AppTheme.colors.textPrimary }}>{gift.name}</h4>
                    <p style={{ margin: '4px 0', fontSize: '14px', color: AppTheme.colors.textSecondary }}>From <span style={{ color: AppTheme.colors.primaryPink, fontWeight: '700' }}>{gift.senderName}</span></p>
                    <span style={{ fontSize: '12px', color: AppTheme.colors.textTertiary }}>{gift.date}</span>
                </div>
                {gift.status !== 'pending' && (
                    <div style={{ padding: '8px 16px', borderRadius: '12px', background: `${AppTheme.colors.successGreen}15`, color: AppTheme.colors.successGreen, fontWeight: '700', fontSize: '13px' }}>
                        Accepted
                    </div>
                )}
            </div>

            {gift.status === 'pending' && (
                <div style={{ display: 'flex', gap: '12px' }}>
                    <motion.button
                        whileTap={{ scale: 0.95 }}
                        onClick={onAccept}
                        style={{ flex: 1, height: '44px', borderRadius: '14px', background: AppTheme.colors.primaryPink, color: '#fff', border: 'none', fontWeight: '700', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}
                    >
                        <FaCheck /> Accept
                    </motion.button>
                    <motion.button
                        whileTap={{ scale: 0.95 }}
                        onClick={onDecline}
                        style={{ flex: 1, height: '44px', borderRadius: '14px', background: '#F3F4F6', color: AppTheme.colors.textSecondary, border: 'none', fontWeight: '700', cursor: 'pointer' }}
                    >
                        Decline
                    </motion.button>
                </div>
            )}
        </div>
    </motion.div>
);

export default Gifts;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import GlassCard from '../components/common/GlassCard';
import PremiumButton from '../components/common/PremiumButton';
import BoostButton from '../components/common/BoostButton';
import PassportModal from '../components/common/PassportModal';
import VerifyEmailBanner from '../components/common/VerifyEmailBanner';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { userService } from '../services/user.service';
import { premiumService } from '../services/premium.service';
import BoostRadar from '../components/common/BoostRadar';
import AdvancedFiltersModal from '../components/common/AdvancedFiltersModal';
import { AppTheme } from '../theme/AppTheme';

const Home = () => {
    const navigate = useNavigate();
    const [users, setUsers] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [showMatchModal, setShowMatchModal] = useState(false);
    const [lastMatchedUser, setLastMatchedUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const { user: authUser } = useAuth();
    const { showToast } = useToast();

    // Premium States
    const [showPassport, setShowPassport] = useState(false);
    const [showFilters, setShowFilters] = useState(false);
    const [isBoosted, setIsBoosted] = useState(false);
    const [boostExpiresAt, setBoostExpiresAt] = useState(null);
    const [currentLocation, setCurrentLocation] = useState(null);
    const [filters, setFilters] = useState({
        ageRange: [18, 50],
        maxDistance: 50,
        height: 'Any',
        religion: 'Any',
        zodiac: 'Any',
        aiVibeMatch: false
    });

    useEffect(() => {
        let isMounted = true;
        const fetchUsers = async () => {
            try {
                const data = await userService.getRecommendations();
                if (isMounted) {
                    setUsers(Array.isArray(data) ? data : []);
                }
            } catch (err) {
                console.error("Failed to fetch recommendations:", err);
                if (isMounted) setError("Could not find people nearby. Please try again.");
            } finally {
                if (isMounted) setLoading(false);
            }
        };
        fetchUsers();
        return () => { isMounted = false; };
    }, []);

    const handleApplyFilters = async (newFilters) => {
        setFilters(newFilters);
        setLoading(true);
        try {
            // Simulate filter application
            const data = await userService.getRecommendations();
            setUsers(data || []);
            showToast("Filters applied successfully! ✨", "success");
        } catch (err) {
            showToast("Failed to refresh feed.", "error");
        } finally {
            setLoading(false);
        }
    };

    const handleSwipe = async (direction) => {
        if (direction === 'gift') {
            navigate('/gifts');
            return;
        }
        if (users && currentIndex < users.length) {
            const currentUser = users[currentIndex];
            const action = direction === 'right' ? 'like' : (direction === 'left' ? 'pass' : 'superlike');

            try {
                const result = await userService.swipe(currentUser.id, action);
                if (direction === 'right' && result?.matched) {
                    setLastMatchedUser(currentUser);
                    setTimeout(() => setShowMatchModal(true), 300);
                }
            } catch (error) {
                console.error("Swipe action failed:", error);
            }

            setTimeout(() => {
                setCurrentIndex(prev => prev + 1);
            }, 200);
        }
    };

    const handleBoost = async () => {
        try {
            const result = await premiumService.activateBoost();
            setIsBoosted(true);
            setBoostExpiresAt(result.boostExpiresAt);
            showToast("Profile Boosted! 🚀 You are now a top match.", "success");
        } catch (err) {
            showToast("Premium feature: Upgrade to use Boost.", "error");
        }
    };

    const handlePassportSelect = async (location) => {
        try {
            if (location) {
                await premiumService.updatePassport({
                    active: true,
                    latitude: location.lat,
                    longitude: location.lon,
                    city: location.city,
                    country: location.country
                });
                setCurrentLocation(location.city);
                showToast(`Passport active: Welcome to ${location.city}! ✈️`, "success");
            } else {
                await premiumService.updatePassport({ active: false });
                setCurrentLocation(null);
                showToast("Returned to your local area.", "success");
            }
            setShowPassport(false);
            // Refresh feed
            setLoading(true);
            const data = await userService.getRecommendations();
            setUsers(data || []);
            setLoading(false);
        } catch (err) {
            showToast("Premium feature: Upgrade to use Passport.", "error");
        }
    };

    const currentUser = users[currentIndex] || null;

    if (error) {
        return (
            <div className="flex-center" style={{ height: '100vh', background: AppTheme.colors.lightBackground, flexDirection: 'column' }}>
                <h2 style={{ color: AppTheme.colors.primaryPink, fontWeight: '700' }}>{error}</h2>
                <PremiumButton text="Retry" type="outline" onClick={() => window.location.reload()} style={{ marginTop: '20px' }} />
            </div>
        );
    }

    return (
        <div style={{ minHeight: '100vh', background: AppTheme.colors.lightBackground, position: 'relative', overflow: 'hidden' }}>
            <BoostRadar isActive={isBoosted} />
            {/* Friendly Header */}
            <header
                style={{
                    position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000,
                    padding: '24px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    background: 'rgba(255, 255, 255, 0.9)', backdropFilter: 'blur(20px)',
                    borderBottom: '1px solid #F3F4F6'
                }}
            >
                <motion.div
                    whileTap={{ scale: 0.9 }}
                    onClick={() => navigate('/profile')}
                    style={{ width: '40px', height: '40px', borderRadius: '50%', background: '#F3F4F6', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                    <FaUser size={16} color={AppTheme.colors.textSecondary} />
                </motion.div>

                <div
                    onClick={() => setShowPassport(true)}
                    style={{ textAlign: 'center', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' }}
                >
                    <div style={{
                        width: '32px', height: '32px', borderRadius: '10px',
                        background: AppTheme.gradients.primary, display: 'flex', alignItems: 'center', justifyContent: 'center'
                    }}>
                        <FaHeart size={14} color="white" />
                    </div>
                    <div>
                        <h1 style={{ fontSize: '20px', margin: 0, fontWeight: '800', letterSpacing: '-0.5px', color: AppTheme.colors.primaryPink }}>
                            Trish
                        </h1>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '10px', color: AppTheme.colors.textSecondary, fontWeight: '700' }}>
                            <FaMapMarkerAlt size={8} /> {currentLocation || 'Nearby'}
                        </div>
                    </div>
                </div>

                <motion.div
                    whileTap={{ scale: 0.9 }}
                    onClick={() => setShowFilters(true)}
                    style={{ width: '40px', height: '40px', borderRadius: '50%', background: '#F3F4F6', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                    <FaSlidersH size={16} color={AppTheme.colors.textSecondary} />
                </motion.div>
            </header>

            <div style={{ paddingTop: '88px', position: 'fixed', top: 0, left: 0, right: 0, zIndex: 900 }}>
                {!authUser?.emailVerified && <VerifyEmailBanner user={authUser} />}

                {/* Quick Radius Toggle */}
                <div style={{
                    padding: '8px 20px 16px',
                    background: 'rgba(255, 255, 255, 0.9)',
                    backdropFilter: 'blur(20px)',
                    display: 'flex',
                    justifyContent: 'center',
                    gap: '12px'
                }}>
                    {[
                        { label: 'Nearby', value: 10 },
                        { label: 'Local', value: 50 },
                        { label: 'Long', value: 500 }
                    ].map(radius => (
                        <motion.button
                            key={radius.label}
                            whileTap={{ scale: 0.95 }}
                            onClick={() => handleApplyFilters({ ...filters, maxDistance: radius.value })}
                            style={{
                                padding: '6px 16px',
                                borderRadius: '12px',
                                background: filters.maxDistance === radius.value ? AppTheme.colors.primaryPink : '#F3F4F6',
                                color: filters.maxDistance === radius.value ? '#FFF' : AppTheme.colors.textSecondary,
                                border: 'none',
                                fontSize: '12px',
                                fontWeight: '800',
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                boxShadow: filters.maxDistance === radius.value ? '0 4px 10px rgba(253, 41, 123, 0.2)' : 'none'
                            }}
                        >
                            {radius.label}
                        </motion.button>
                    ))}
                </div>
            </div>

            <main style={{
                paddingTop: '100px', paddingBottom: '120px', display: 'flex', flexDirection: 'column',
                alignItems: 'center', minHeight: '90vh'
            }}>
                <AnimatePresence mode='wait'>
                    {loading ? (
                        <motion.div key="loading" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} style={{ textAlign: 'center', marginTop: '100px' }}>
                            <div style={{ width: '80px', height: '80px', borderRadius: '50%', background: AppTheme.gradients.primary, display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 20px', boxShadow: AppTheme.shadows.glow }}>
                                <motion.div
                                    animate={{ scale: [1, 1.2, 1] }}
                                    transition={{ repeat: Infinity, duration: 1.5 }}
                                >
                                    <FaHeart size={32} color="white" />
                                </motion.div>
                            </div>
                            <h3 style={{ fontSize: '18px', fontWeight: '800', color: AppTheme.colors.textPrimary }}>Searching for connections...</h3>
                        </motion.div>
                    ) : currentUser ? (
                        <div key="content" style={{ width: '100%', maxWidth: '420px', padding: '0 16px' }}>
                            {/* Discovery Row */}
                            <motion.div
                                initial={{ opacity: 0, y: -20 }}
                                animate={{ opacity: 1, y: 0 }}
                                style={{ marginBottom: '24px', overflowX: 'auto', display: 'flex', gap: '16px', paddingBottom: '12px', scrollbarWidth: 'none' }}
                            >
                                {users.slice(currentIndex + 1, currentIndex + 6).map((u, i) => (
                                    <motion.div key={u.id} whileHover={{ scale: 1.05 }} style={{ minWidth: '64px', textAlign: 'center' }}>
                                        <div style={{ width: '64px', height: '64px', borderRadius: '20px', border: `2px solid #E5E7EB`, padding: '2px', position: 'relative', overflow: 'hidden' }}>
                                            <img src={u.photos?.[0] || 'https://via.placeholder.com/100'} alt="" style={{ width: '100%', height: '100%', borderRadius: '16px', objectFit: 'cover' }} />
                                            <div style={{ position: 'absolute', bottom: '2px', right: '2px', width: '12px', height: '12px', borderRadius: '50%', background: AppTheme.colors.successGreen, border: '2px solid #FFFFFF' }} />
                                        </div>
                                    </motion.div>
                                ))}
                            </motion.div>

                            {/* Blind Date Premium Banner */}
                            <motion.div
                                whileTap={{ scale: 0.98 }}
                                onClick={() => navigate('/blind-date')}
                                style={{
                                    marginBottom: '24px',
                                    padding: '20px',
                                    borderRadius: '24px',
                                    background: 'linear-gradient(135deg, #1e1b4b 0%, #312e81 100%)',
                                    color: '#fff',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '16px',
                                    cursor: 'pointer',
                                    position: 'relative',
                                    overflow: 'hidden',
                                    boxShadow: '0 12px 30px rgba(30, 27, 75, 0.4)',
                                    border: '1px solid rgba(255,255,255,0.1)'
                                }}
                            >
                                <div style={{ position: 'absolute', top: '-20px', right: '-20px', width: '80px', height: '80px', borderRadius: '50%', background: 'rgba(99, 102, 241, 0.2)', filter: 'blur(30px)' }} />

                                <div style={{
                                    width: '56px',
                                    height: '56px',
                                    borderRadius: '16px',
                                    background: 'rgba(255,255,255,0.1)',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    color: '#FBBF24',
                                    boxShadow: 'inset 0 0 10px rgba(255,255,255,0.1)'
                                }}>
                                    <FaEyeSlash size={24} />
                                </div>
                                <div style={{ flex: 1 }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                        <h4 style={{ margin: 0, fontSize: '18px', fontWeight: '800' }}>Blind Date Mode</h4>
                                        <span style={{ fontSize: '10px', background: 'rgba(251, 191, 36, 0.2)', color: '#FBBF24', padding: '2px 8px', borderRadius: '10px', fontWeight: '800' }}>PREMIUM</span>
                                    </div>
                                    <p style={{ margin: '4px 0 0 0', fontSize: '13px', color: 'rgba(255,255,255,0.6)', fontWeight: '500' }}>Match based on soul, not just photos.</p>
                                </div>
                                <FaMagic color="#FBBF24" size={16} />
                            </motion.div>

                            <ProfileCard user={currentUser} onSwipe={handleSwipe} />
                        </div>
                    ) : (
                        <motion.div key="empty" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} style={{ textAlign: 'center', padding: '0 20px', marginTop: '100px' }}>
                            <GlassCard style={{ padding: '40px 30px', borderRadius: '32px', background: '#fff', border: '1px solid #F3F4F6', boxShadow: '0 20px 40px rgba(0,0,0,0.05)' }}>
                                <div style={{ width: '80px', height: '80px', borderRadius: '40px', background: '#F9FAFB', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 24px' }}>
                                    <FaSearchLocation size={32} color={AppTheme.colors.textSecondary} />
                                </div>
                                <h2 style={{ fontSize: '24px', marginBottom: '12px', color: AppTheme.colors.textPrimary, fontWeight: '800' }}>Out of people!</h2>
                                <p style={{ color: AppTheme.colors.textSecondary, marginBottom: '32px', lineHeight: '1.6', fontSize: '15px' }}>Check back later or expand your discovery filters to find more great connections.</p>
                                <PremiumButton text="Adjust Filters" type="gradient" fullWidth onClick={() => setShowFilters(true)} />
                            </GlassCard>
                        </motion.div>
                    )}
                </AnimatePresence>
            </main>

            <MatchModal
                isOpen={showMatchModal}
                user={lastMatchedUser || { name: 'Match', photos: [] }}
                onClose={() => setShowMatchModal(false)}
                onChat={() => { setShowMatchModal(false); navigate('/chat'); }}
            />

            <BoostButton
                isActive={isBoosted}
                expiresAt={boostExpiresAt}
                onBoost={handleBoost}
            />

            <PassportModal
                isOpen={showPassport}
                currentCity={currentLocation}
                onClose={() => setShowPassport(false)}
                onSelect={handlePassportSelect}
            />

            <AdvancedFiltersModal
                isOpen={showFilters}
                onClose={() => setShowFilters(false)}
                onApply={handleApplyFilters}
                currentFilters={filters}
            />
        </div>
    );
};

export default Home;

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FaShieldAlt, FaCamera, FaCheckCircle, FaExclamationTriangle, FaArrowLeft, FaIdCard, FaUserCheck, FaFileAlt } from 'react-icons/fa';
import { AppTheme } from '../theme/AppTheme';
import { useNavigate } from 'react-router-dom';
import PremiumButton from '../components/common/PremiumButton';
import { useToast } from '../context/ToastContext';

const KYC_STEPS = [
    {
        id: 'start',
        title: 'Get Verified',
        desc: 'Join the circle of trust. Verified profiles get 3x more matches and priority placement.',
        icon: FaShieldAlt,
        color: AppTheme.colors.brandBlue
    },
    {
        id: 'document',
        title: 'Upload ID',
        desc: 'Take a clear photo of your ID card or Passport for identity confirmation.',
        icon: FaIdCard,
        color: '#6366F1'
    },
    {
        id: 'selfie',
        title: 'Liveness Check',
        desc: 'Take a selfie to prove this is your account. We use AI to match it with your ID.',
        icon: FaCamera,
        color: AppTheme.colors.primaryPink
    },
    {
        id: 'processing',
        title: 'Verifying...',
        desc: 'Our AI engine is currently validating your identity documents.',
        icon: FaUserCheck,
        color: '#FBBF24'
    },
    {
        id: 'success',
        title: 'Verified!',
        desc: 'Congratulations! Your profile now bears the blue checkmark of trust.',
        icon: FaCheckCircle,
        color: AppTheme.colors.successGreen
    }
];

const KYC = () => {
    const [currentStep, setCurrentStep] = useState(0);
    const [capturedSelfie, setCapturedSelfie] = useState(null);
    const [capturedDoc, setCapturedDoc] = useState(null);
    const [isScanning, setIsScanning] = useState(false);
    const videoRef = useRef(null);
    const navigate = useNavigate();
    const { showToast } = useToast();

    const nextStep = () => setCurrentStep(prev => prev + 1);

    const startCamera = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ video: true });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
        } catch (err) {
            console.error("Camera access denied:", err);
            showToast("Camera access is required for verification.", "error");
        }
    };

    const takePhoto = () => {
        setIsScanning(true);
        setTimeout(() => {
            setCapturedSelfie("https://images.unsplash.com/photo-1539571696357-5a69c17a67c6?w=600");
            setIsScanning(false);
            nextStep();
        }, 3000);
    };

    const handleFileUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            setCapturedDoc(URL.createObjectURL(file));
            nextStep();
        }
    };

    const simulateProcessing = () => {
        setTimeout(() => {
            nextStep();
        }, 5000);
    };

    useEffect(() => {
        if (KYC_STEPS[currentStep].id === 'selfie' && !capturedSelfie) {
            startCamera();
        }
        if (KYC_STEPS[currentStep].id === 'processing') {
            simulateProcessing();
        }
    }, [currentStep, capturedSelfie]);

    const currentStepData = KYC_STEPS[currentStep];

    return (
        <div style={{
            minHeight: '100vh',
            background: AppTheme.colors.lightBackground,
            color: AppTheme.colors.textPrimary,
            padding: '24px',
            display: 'flex',
            flexDirection: 'column',
            position: 'relative',
            overflow: 'hidden'
        }}>
            {/* Header */}
            <header style={{ marginBottom: '40px', display: 'flex', alignItems: 'center', gap: '16px' }}>
                <motion.button
                    whileTap={{ scale: 0.9 }}
                    onClick={() => currentStep === 0 ? navigate(-1) : setCurrentStep(prev => prev - 1)}
                    style={{ width: '40px', height: '40px', borderRadius: '50%', background: '#FFF', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 2px 10px rgba(0,0,0,0.05)', cursor: 'pointer' }}
                >
                    <FaArrowLeft size={16} />
                </motion.button>
                <h1 style={{ fontSize: '20px', fontWeight: '800', margin: 0 }}>Identity Verification</h1>
            </header>

            <AnimatePresence mode="wait">
                <motion.div
                    key={currentStep}
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center' }}
                >
                    <div style={{ textAlign: 'center', marginBottom: '48px', maxWidth: '400px' }}>
                        <div style={{
                            width: '80px', height: '80px', borderRadius: '50%',
                            background: `${currentStepData.color}20`,
                            color: currentStepData.color,
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            margin: '0 auto 24px'
                        }}>
                            <currentStepData.icon size={36} />
                        </div>
                        <h2 style={{ fontSize: '28px', fontWeight: '800', marginBottom: '12px' }}>{currentStepData.title}</h2>
                        <p style={{ color: AppTheme.colors.textSecondary, fontSize: '16px', lineHeight: '1.6', maxWidth: '300px', margin: '0 auto' }}>
                            {currentStepData.desc}
                        </p>
                    </div>

                    {/* Step Specific Content */}
                    <div style={{ flex: 1, width: '100%', maxWidth: '400px' }}>
                        {currentStepData.id === 'start' && (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
                                <FeatureItem icon={FaShieldAlt} text="Verified Badge on Profile" />
                                <FeatureItem icon={FaUserCheck} text="Trust with Potential Matches" />
                                <FeatureItem icon={FaCheckCircle} text="Priority in Search Feed" />
                            </div>
                        )}

                        {currentStepData.id === 'document' && (
                            <div style={{ textAlign: 'center' }}>
                                <input
                                    type="file"
                                    id="doc-upload"
                                    hidden
                                    accept="image/*"
                                    onChange={handleFileUpload}
                                />
                                <label htmlFor="doc-upload" style={{ cursor: 'pointer' }}>
                                    <div style={{
                                        width: '100%', height: '240px', borderRadius: '24px',
                                        border: '2px dashed #E5E7EB', display: 'flex',
                                        flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                                        background: '#FFF', boxShadow: '0 4px 15px rgba(0,0,0,0.02)'
                                    }}>
                                        <FaFileAlt size={48} color="#E5E7EB" style={{ marginBottom: '16px' }} />
                                        <span style={{ fontWeight: '700', color: AppTheme.colors.textSecondary }}>Scan your ID or Passport</span>
                                    </div>
                                </label>
                            </div>
                        )}

                        {currentStepData.id === 'selfie' && (
                            <div style={{ position: 'relative', width: '100%', height: '380px', borderRadius: '32px', overflow: 'hidden', background: '#000', boxShadow: '0 20px 40px rgba(0,0,0,0.2)' }}>
                                <video
                                    ref={videoRef}
                                    autoPlay
                                    playsInline
                                    style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                                />
                                {/* Face Overlay Guide */}
                                <div style={{
                                    position: 'absolute', inset: 0,
                                    border: '40px solid rgba(0,0,0,0.5)',
                                    display: 'flex', alignItems: 'center', justifyContent: 'center'
                                }}>
                                    <div style={{
                                        width: '220px', height: '280px', borderRadius: '110px / 140px',
                                        border: `2px solid ${isScanning ? AppTheme.colors.primaryPink : '#FFF'}`,
                                        boxShadow: '0 0 0 1000px rgba(0,0,0,0.3)'
                                    }} />
                                </div>

                                {isScanning && (
                                    <motion.div
                                        animate={{ top: ['15%', '85%', '15%'] }}
                                        transition={{ duration: 2, repeat: Infinity }}
                                        style={{
                                            position: 'absolute', left: '20%', right: '20%',
                                            height: '2px', background: AppTheme.colors.primaryPink,
                                            boxShadow: `0 0 20px ${AppTheme.colors.primaryPink}`,
                                            zIndex: 10
                                        }}
                                    />
                                )}
                            </div>
                        )}

                        {currentStepData.id === 'processing' && (
                            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', padding: '40px 0' }}>
                                <div style={{ position: 'relative', width: '220px', height: '220px' }}>
                                    <motion.div
                                        animate={{ rotate: 360 }}
                                        transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
                                        style={{
                                            position: 'absolute', inset: -4, borderRadius: '50%',
                                            border: '4px solid transparent',
                                            borderTopColor: AppTheme.colors.primaryPink,
                                            borderRightColor: AppTheme.colors.brandBlue
                                        }}
                                    />
                                    <div style={{
                                        position: 'absolute', inset: '10px', borderRadius: '50%',
                                        overflow: 'hidden', border: '1px solid #E5E7EB',
                                        background: '#FFF'
                                    }}>
                                        {capturedSelfie && <img src={capturedSelfie} alt="Processing" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
                                    </div>
                                    <motion.div
                                        animate={{ scale: [1, 1.2, 1], opacity: [0.8, 1, 0.8] }}
                                        transition={{ duration: 2, repeat: Infinity }}
                                        style={{
                                            position: 'absolute', top: '-10px', right: '-10px',
                                            background: '#FBBF24', color: '#FFF', padding: '12px',
                                            borderRadius: '50%', boxShadow: '0 8px 20px rgba(251, 191, 36, 0.4)',
                                            zIndex: 5
                                        }}
                                    >
                                        <FaUserCheck size={20} />
                                    </motion.div>
                                </div>
                                <div style={{ marginTop: '48px', textAlign: 'center', width: '100%' }}>
                                    <div style={{ fontSize: '12px', fontWeight: '800', color: AppTheme.colors.textTertiary, letterSpacing: '3px', marginBottom: '12px' }}>NEURAL COMPARISON ACTIVE</div>
                                    <div style={{ width: '100%', height: '4px', background: '#F3F4F6', borderRadius: '2px', overflow: 'hidden' }}>
                                        <motion.div
                                            initial={{ width: '0%' }}
                                            animate={{ width: '100%' }}
                                            transition={{ duration: 5, ease: "easeInOut" }}
                                            style={{ height: '100%', background: AppTheme.gradients.primary }}
                                        />
                                    </div>
                                </div>
                            </div>
                        )}

                        {currentStepData.id === 'success' && (
                            <div style={{ textAlign: 'center', padding: '40px 0' }}>
                                <motion.div
                                    initial={{ scale: 0, rotate: -180 }}
                                    animate={{ scale: 1, rotate: 0 }}
                                    transition={{ type: 'spring', damping: 12, stiffness: 100 }}
                                    style={{
                                        width: '140px', height: '140px', borderRadius: '50%',
                                        background: AppTheme.colors.successGreen, color: '#FFF',
                                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                                        margin: '0 auto 32px', boxShadow: '0 15px 40px rgba(34, 197, 94, 0.4)',
                                        border: '4px solid #FFF'
                                    }}
                                >
                                    <FaCheckCircle size={70} />
                                </motion.div>
                                <p style={{ fontSize: '18px', color: AppTheme.colors.textSecondary, marginBottom: '32px', lineHeight: '1.6' }}>
                                    Verification complete! Our AI has confirmed your identity. Welcome to the trusted inner circle.
                                </p>
                            </div>
                        )}
                    </div>

                    {/* Footer Actions */}
                    <div style={{ marginTop: '32px', width: '100%', maxWidth: '400px' }}>
                        {currentStepData.id === 'start' && (
                            <PremiumButton text="Start Multi-Factor Auth" type="gradient" fullWidth onClick={nextStep} />
                        )}
                        {currentStepData.id === 'selfie' && (
                            <PremiumButton
                                text={isScanning ? "Processing Biometrics..." : "Scan My Face"}
                                type="gradient"
                                fullWidth
                                onClick={takePhoto}
                                isLoading={isScanning}
                            />
                        )}
                        {currentStepData.id === 'success' && (
                            <PremiumButton text="Proceed to Premium Feed" type="gradient" fullWidth onClick={() => navigate('/profile')} />
                        )}
                    </div>
                </motion.div>
            </AnimatePresence>
        </div>
    );
};

const FeatureItem = ({ icon: Icon, text }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '16px', padding: '18px 24px', borderRadius: '24px', background: '#FFF', border: '1px solid #E5E7EB', boxShadow: '0 2px 10px rgba(0,0,0,0.02)' }}>
        <div style={{ color: AppTheme.colors.primaryPink }}>
            <Icon size={22} />
        </div>
        <span style={{ fontWeight: '700', color: AppTheme.colors.textPrimary, fontSize: '15px' }}>{text}</span>
    </div>
);

export default KYC;

