import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FaArrowLeft, FaCamera, FaMagic, FaCheck, FaTimes, FaPlus, FaBriefcase, FaGraduationCap, FaStar, FaGlobe, FaWineGlassAlt, FaSmoking, FaChild, FaPaw, FaSpinner } from 'react-icons/fa';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { userService } from '../services/user.service';
import { aiService } from '../services/ai.service';
import { AppTheme } from '../theme/AppTheme';

const ProfileEdit = () => {
    const { user: authUser, setUser } = useAuth();
    const navigate = useNavigate();
    const { showToast } = useToast();
    const [loading, setLoading] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);

    const [form, setForm] = useState({
        name: authUser?.name || '',
        bio: authUser?.bio || '',
        interests: authUser?.interests || [],
        lifestyle: authUser?.lifestyle || {
            job: '',
            education: '',
            zodiac: '',
            languages: [],
            drinking: '',
            smoking: '',
            kids: '',
            pets: ''
        }
    });

    const [newInterest, setNewInterest] = useState('');
    const [selectedTone, setSelectedTone] = useState('witty');

    const handleSave = async () => {
        setLoading(true);
        try {
            const updatedUser = await userService.updateProfile(form);
            setUser(updatedUser);
            showToast("Profile updated successfully! ✨", "success");
            navigate('/profile');
        } catch (error) {
            showToast("Failed to update profile.", "error");
        } finally {
            setLoading(false);
        }
    };

    const handleGenerateBio = async () => {
        setIsGenerating(true);
        try {
            const traits = {
                mbti: authUser?.mbti || 'INTJ',
                enneagram: authUser?.enneagram || '5w6',
                interests: form.interests,
                lifestyle: form.lifestyle,
                tone: selectedTone
            };
            const aiBio = await aiService.generateBio(traits);
            setForm(prev => ({ ...prev, bio: aiBio }));
            showToast("AI Bio Generated! 🤖✨", "success");
        } catch (error) {
            showToast("AI Generation failed. Try again.", "error");
        } finally {
            setIsGenerating(false);
        }
    };

    const addInterest = () => {
        if (newInterest && !form.interests.includes(newInterest)) {
            setForm(prev => ({ ...prev, interests: [...prev.interests, newInterest] }));
            setNewInterest('');
        }
    };

    const removeInterest = (interest) => {
        setForm(prev => ({ ...prev, interests: prev.interests.filter(i => i !== interest) }));
    };

    return (
        <div style={{
            minHeight: '100vh',
            background: AppTheme.colors.lightBackground,
            paddingBottom: '120px'
        }}>
            {/* Header */}
            <div style={{
                position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000,
                padding: '20px', display: 'flex', justifyContent: 'space-between',
                alignItems: 'center', background: 'rgba(255, 255, 255, 0.9)',
                backdropFilter: 'blur(20px)', borderBottom: '1px solid #F3F4F6'
            }}>
                <motion.div whileTap={{ scale: 0.9 }} onClick={() => navigate(-1)} style={{ cursor: 'pointer', color: AppTheme.colors.textPrimary }}>
                    <FaArrowLeft size={20} />
                </motion.div>
                <h2 style={{ fontSize: '18px', fontWeight: '800', margin: 0 }}>Edit Profile</h2>
                <motion.button
                    whileTap={{ scale: 0.95 }}
                    onClick={handleSave}
                    disabled={loading}
                    style={{
                        background: 'none', border: 'none', color: AppTheme.colors.primaryPink,
                        fontWeight: '800', fontSize: '16px', cursor: 'pointer'
                    }}
                >
                    {loading ? <FaSpinner className="spin" /> : 'Save'}
                </motion.button>
            </div>

            <main style={{ paddingTop: '100px', padding: '100px 24px 24px' }}>
                {/* Photo Upload Placeholder */}
                <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '32px' }}>
                    <div style={{ position: 'relative' }}>
                        <img
                            src={authUser?.photos?.[0] || 'https://via.placeholder.com/150'}
                            style={{ width: '120px', height: '120px', borderRadius: '32px', objectFit: 'cover', border: `4px solid #fff`, boxShadow: '0 10px 25px rgba(0,0,0,0.1)' }}
                        />
                        <div style={{
                            position: 'absolute', bottom: '-10px', right: '-10px',
                            width: '40px', height: '40px', borderRadius: '50%',
                            background: AppTheme.colors.primaryPink, color: '#fff',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            boxShadow: '0 4px 10px rgba(253, 41, 123, 0.3)', cursor: 'pointer'
                        }}>
                            <FaCamera size={16} />
                        </div>
                    </div>
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', gap: '32px' }}>
                    {/* Bio Section with AI */}
                    <section>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                            <label style={{ fontSize: '14px', fontWeight: '800', color: AppTheme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '1px' }}>About Me</label>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                <select
                                    value={selectedTone}
                                    onChange={(e) => setSelectedTone(e.target.value)}
                                    style={{
                                        padding: '4px 8px', borderRadius: '8px', border: '1px solid #E5E7EB',
                                        fontSize: '12px', fontWeight: '600', outline: 'none'
                                    }}
                                >
                                    <option value="witty">Witty</option>
                                    <option value="romantic">Romantic</option>
                                    <option value="casual">Casual</option>
                                    <option value="professional">Professional</option>
                                </select>
                                <motion.button
                                    whileHover={{ scale: 1.05 }}
                                    whileTap={{ scale: 0.95 }}
                                    onClick={handleGenerateBio}
                                    disabled={isGenerating}
                                    style={{
                                        display: 'flex', alignItems: 'center', gap: '6px',
                                        background: 'linear-gradient(135deg, #6366F1 0%, #8B5CF6 100%)',
                                        padding: '6px 12px', borderRadius: '12px', border: 'none',
                                        color: '#fff', fontSize: '11px', fontWeight: '800', cursor: 'pointer',
                                        boxShadow: '0 4px 10px rgba(99, 102, 241, 0.3)'
                                    }}
                                >
                                    {isGenerating ? <FaSpinner className="spin" size={12} /> : <FaMagic size={12} />}
                                    AI GEN
                                </motion.button>
                            </div>
                        </div>
                        <textarea
                            value={form.bio}
                            onChange={(e) => setForm(prev => ({ ...prev, bio: e.target.value }))}
                            placeholder="Write something about yourself..."
                            style={{
                                width: '100%', minHeight: '120px', padding: '16px', borderRadius: '20px',
                                background: '#fff', border: '1px solid #E5E7EB', fontSize: '15px',
                                lineHeight: '1.6', outline: 'none', resize: 'vertical'
                            }}
                        />
                    </section>

                    {/* Interests Chips */}
                    <section>
                        <label style={{ fontSize: '14px', fontWeight: '800', color: AppTheme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '1px', display: 'block', marginBottom: '16px' }}>Interests</label>
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', marginBottom: '16px' }}>
                            {form.interests.map(interest => (
                                <motion.div
                                    key={interest}
                                    initial={{ scale: 0.8 }}
                                    animate={{ scale: 1 }}
                                    style={{
                                        padding: '8px 16px', borderRadius: '20px', background: '#fff',
                                        border: `1px solid ${AppTheme.colors.primaryPink}40`,
                                        color: AppTheme.colors.primaryPink, fontSize: '13px', fontWeight: '700',
                                        display: 'flex', alignItems: 'center', gap: '8px'
                                    }}
                                >
                                    {interest}
                                    <FaTimes onClick={() => removeInterest(interest)} style={{ cursor: 'pointer', opacity: 0.6 }} />
                                </motion.div>
                            ))}
                        </div>
                        <div style={{ position: 'relative' }}>
                            <input
                                type="text"
                                placeholder="Add an interest..."
                                value={newInterest}
                                onChange={(e) => setNewInterest(e.target.value)}
                                onKeyPress={(e) => e.key === 'Enter' && addInterest()}
                                style={{
                                    width: '100%', padding: '16px 50px 16px 20px', borderRadius: '20px',
                                    background: '#fff', border: '1px solid #E5E7EB', fontSize: '15px',
                                    outline: 'none'
                                }}
                            />
                            <div
                                onClick={addInterest}
                                style={{
                                    position: 'absolute', right: '12px', top: '50%', transform: 'translateY(-50%)',
                                    width: '32px', height: '32px', borderRadius: '50%',
                                    background: AppTheme.colors.primaryPink, color: '#fff',
                                    display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer'
                                }}
                            >
                                <FaPlus size={12} />
                            </div>
                        </div>
                    </section>

                    {/* Lifestyle Essentials */}
                    <section>
                        <label style={{ fontSize: '14px', fontWeight: '800', color: AppTheme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '1px', display: 'block', marginBottom: '16px' }}>The Essentials</label>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '12px' }}>
                            <GridInput icon={FaBriefcase} label="Work" value={form.lifestyle.job} onChange={(val) => setForm(p => ({ ...p, lifestyle: { ...p.lifestyle, job: val } }))} />
                            <GridInput icon={FaGraduationCap} label="Education" value={form.lifestyle.education} onChange={(val) => setForm(p => ({ ...p, lifestyle: { ...p.lifestyle, education: val } }))} />
                            <GridInput icon={FaStar} label="Zodiac" value={form.lifestyle.zodiac} onChange={(val) => setForm(p => ({ ...p, lifestyle: { ...p.lifestyle, zodiac: val } }))} />
                            <GridInput icon={FaWineGlassAlt} label="Drinking" value={form.lifestyle.drinking} onChange={(val) => setForm(p => ({ ...p, lifestyle: { ...p.lifestyle, drinking: val } }))} />
                            <GridInput icon={FaSmoking} label="Smoking" value={form.lifestyle.smoking} onChange={(val) => setForm(p => ({ ...p, lifestyle: { ...p.lifestyle, smoking: val } }))} />
                            <GridInput icon={FaChild} label="Kids" value={form.lifestyle.kids} onChange={(val) => setForm(p => ({ ...p, lifestyle: { ...p.lifestyle, kids: val } }))} />
                            <GridInput icon={FaPaw} label="Pets" value={form.lifestyle.pets} onChange={(val) => setForm(p => ({ ...p, lifestyle: { ...p.lifestyle, pets: val } }))} />
                        </div>
                    </section>
                </div>
            </main>
        </div>
    );
};

const GridInput = ({ icon: Icon, label, value, onChange }) => (
    <div style={{
        display: 'flex', alignItems: 'center', gap: '12px',
        padding: '12px 16px', borderRadius: '16px', background: '#FFFFFF',
        border: '1px solid #E5E7EB'
    }}>
        <Icon color={AppTheme.colors.textSecondary} size={16} />
        <div style={{ flex: 1 }}>
            <span style={{ fontSize: '11px', fontWeight: '800', color: AppTheme.colors.textTertiary, display: 'block' }}>{label}</span>
            <input
                type="text"
                value={value}
                onChange={(e) => onChange(e.target.value)}
                style={{
                    width: '100%', border: 'none', background: 'transparent',
                    fontSize: '15px', fontWeight: '600', color: AppTheme.colors.textPrimary,
                    outline: 'none', padding: '2px 0'
                }}
            />
        </div>
    </div>
);

export default ProfileEdit;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { FaUser, FaEnvelope, FaLock, FaCalendar, FaVenusMars, FaHeart, FaArrowRight, FaArrowLeft } from 'react-icons/fa';
import PremiumButton from '../components/common/PremiumButton';
import { AppTheme } from '../theme/AppTheme';
import { useAuth } from '../context/AuthContext';

const Register = () => {
    const navigate = useNavigate();
    const { register } = useAuth();
    const [step, setStep] = useState(1);
    const [formData, setFormData] = useState({
        name: '', email: '', password: '', dateOfBirth: '', gender: 'FEMALE'
    });
    const [isLoading, setIsLoading] = useState(false);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const nextStep = () => {
        if (step === 1 && (!formData.name || !formData.dateOfBirth || !formData.gender)) return;
        setStep(prev => prev + 1);
    };

    const prevStep = () => {
        setStep(prev => prev - 1);
    };

    const handleRegister = async (e) => {
        e.preventDefault();
        if (!formData.email || !formData.password) return;
        setIsLoading(true);
        try {
            await register(formData);
            setTimeout(() => {
                setIsLoading(false);
                navigate('/home');
            }, 1500);
        } catch (error) {
            console.error(error);
            setIsLoading(false);
        }
    };

    return (
        <div style={{
            minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center',
            background: AppTheme.colors.lightBackground, position: 'relative', overflow: 'hidden'
        }}>
            {/* Background Aesthetic */}
            <div style={{ position: 'absolute', inset: 0, zIndex: 0 }}>
                <img
                    src="https://images.unsplash.com/photo-1516195851888-6f1a981a8a2a?w=1600"
                    alt="Background"
                    style={{ width: '100%', height: '100%', objectFit: 'cover', opacity: 0.05 }}
                />
            </div>

            <motion.div
                initial={{ opacity: 0, scale: 0.95, y: 20 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                transition={{ duration: 0.6, ease: "easeOut" }}
                style={{ position: 'relative', zIndex: 10, width: '100%', maxWidth: '460px', padding: '20px' }}
            >
                <div style={{
                    background: '#FFFFFF',
                    padding: '40px 32px',
                    borderRadius: '24px',
                    boxShadow: AppTheme.shadows.card,
                    border: '1px solid rgba(0,0,0,0.02)',
                    minHeight: '520px',
                    display: 'flex',
                    flexDirection: 'column'
                }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
                        {step === 2 ? (
                            <motion.button whileTap={{ scale: 0.9 }} onClick={prevStep} style={{ background: 'none', border: 'none', color: AppTheme.colors.textSecondary, cursor: 'pointer', padding: '8px' }}>
                                <FaArrowLeft size={20} />
                            </motion.button>
                        ) : (
                            <div style={{ width: '36px' }} />
                        )}

                        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                            <div style={{ width: '30px', height: '6px', borderRadius: '3px', background: step >= 1 ? AppTheme.colors.primaryPink : '#E5E7EB', transition: 'background 0.3s' }} />
                            <div style={{ width: '30px', height: '6px', borderRadius: '3px', background: step >= 2 ? AppTheme.colors.primaryPink : '#E5E7EB', transition: 'background 0.3s' }} />
                        </div>
                        <div style={{ width: '36px' }} />
                    </div>

                    <div style={{ textAlign: 'center', marginBottom: '30px' }}>
                        <h1 style={{ fontSize: '28px', fontWeight: '800', color: AppTheme.colors.textPrimary, marginBottom: '8px' }}>
                            {step === 1 ? "Let's get started" : "Secure your account"}
                        </h1>
                        <p style={{ color: AppTheme.colors.textSecondary, fontSize: '15px' }}>
                            {step === 1 ? "Help us customize your experience." : "Almost there! Choose a secure password."}
                        </p>
                    </div>

                    <form onSubmit={(e) => e.preventDefault()} style={{ display: 'flex', flexDirection: 'column', gap: '20px', flex: 1 }}>
                        <AnimatePresence mode="wait">
                            {step === 1 && (
                                <motion.div
                                    key="step1"
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    exit={{ opacity: 0, x: 20 }}
                                    transition={{ duration: 0.3 }}
                                    style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}
                                >
                                    <div style={{ position: 'relative' }}>
                                        <div style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)', color: AppTheme.colors.textTertiary }}>
                                            <FaUser />
                                        </div>
                                        <input
                                            name="name"
                                            type="text"
                                            placeholder="Your First Name"
                                            value={formData.name}
                                            onChange={handleChange}
                                            style={{
                                                width: '100%', padding: '16px 16px 16px 48px', borderRadius: '16px',
                                                border: '1px solid #E5E7EB', background: '#F9FAFB',
                                                color: AppTheme.colors.textPrimary, fontSize: '15px', outline: 'none'
                                            }}
                                            required
                                        />
                                    </div>
                                    <div style={{ position: 'relative' }}>
                                        <div style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)', color: AppTheme.colors.textTertiary }}>
                                            <FaCalendar />
                                        </div>
                                        <input
                                            name="dateOfBirth"
                                            type="date"
                                            value={formData.dateOfBirth}
                                            onChange={handleChange}
                                            style={{
                                                width: '100%', padding: '16px 16px 16px 48px', borderRadius: '16px',
                                                border: '1px solid #E5E7EB', background: '#F9FAFB',
                                                color: formData.dateOfBirth ? AppTheme.colors.textPrimary : AppTheme.colors.textTertiary,
                                                fontSize: '15px', outline: 'none'
                                            }}
                                            required
                                        />
                                    </div>
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                                        <p style={{ fontSize: '14px', fontWeight: '700', color: AppTheme.colors.textSecondary, marginBottom: '4px', textAlign: 'left', paddingLeft: '4px' }}>I am a...</p>
                                        <div style={{ display: 'flex', gap: '10px' }}>
                                            {['Woman', 'Man', 'Other'].map((g) => {
                                                const isSelected = formData.gender.toLowerCase() === g.toLowerCase();
                                                return (
                                                    <motion.div
                                                        key={g}
                                                        whileTap={{ scale: 0.95 }}
                                                        onClick={() => setFormData({ ...formData, gender: g.toUpperCase() })}
                                                        style={{
                                                            flex: 1, padding: '12px', borderRadius: '12px', textAlign: 'center', cursor: 'pointer',
                                                            background: isSelected ? AppTheme.colors.primaryPink : '#F9FAFB',
                                                            color: isSelected ? '#FFFFFF' : AppTheme.colors.textPrimary,
                                                            border: isSelected ? 'none' : '1px solid #E5E7EB',
                                                            fontSize: '14px', fontWeight: '700', transition: 'all 0.2s'
                                                        }}
                                                    >
                                                        {g}
                                                    </motion.div>
                                                );
                                            })}
                                        </div>
                                    </div>
                                    <div style={{ marginTop: 'auto', paddingTop: '20px' }}>
                                        <PremiumButton
                                            text="Continue"
                                            type="gradient"
                                            fullWidth
                                            onClick={nextStep}
                                            icon={FaArrowRight}
                                            style={{ height: '56px', borderRadius: '16px', fontSize: '16px', fontWeight: '700' }}
                                        />
                                    </div>
                                </motion.div>
                            )}

                            {step === 2 && (
                                <motion.div
                                    key="step2"
                                    initial={{ opacity: 0, x: 20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    exit={{ opacity: 0, x: -20 }}
                                    transition={{ duration: 0.3 }}
                                    style={{ display: 'flex', flexDirection: 'column', gap: '20px', height: '100%' }}
                                >
                                    <div style={{ position: 'relative' }}>
                                        <div style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)', color: AppTheme.colors.textTertiary }}>
                                            <FaEnvelope />
                                        </div>
                                        <input
                                            name="email"
                                            type="email"
                                            placeholder="Email address"
                                            value={formData.email}
                                            onChange={handleChange}
                                            style={{
                                                width: '100%', padding: '16px 16px 16px 48px', borderRadius: '16px',
                                                border: '1px solid #E5E7EB', background: '#F9FAFB',
                                                color: AppTheme.colors.textPrimary, fontSize: '15px', outline: 'none'
                                            }}
                                            required
                                        />
                                    </div>
                                    <div style={{ position: 'relative' }}>
                                        <div style={{ position: 'absolute', left: '16px', top: '50%', transform: 'translateY(-50%)', color: AppTheme.colors.textTertiary }}>
                                            <FaLock />
                                        </div>
                                        <input
                                            name="password"
                                            type="password"
                                            placeholder="Create a password"
                                            value={formData.password}
                                            onChange={handleChange}
                                            style={{
                                                width: '100%', padding: '16px 16px 16px 48px', borderRadius: '16px',
                                                border: '1px solid #E5E7EB', background: '#F9FAFB',
                                                color: AppTheme.colors.textPrimary, fontSize: '15px', outline: 'none'
                                            }}
                                            required
                                        />
                                    </div>

                                    {/* Password Strength Indicator */}
                                    {formData.password && (
                                        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                                            <div style={{ display: 'flex', gap: '6px' }}>
                                                {[1, 2, 3, 4].map(level => {
                                                    const strength = formData.password.length >= 12 ? 4 : formData.password.length >= 8 ? 3 : formData.password.length >= 6 ? 2 : 1;
                                                    return (
                                                        <div key={level} style={{
                                                            flex: 1, height: '4px', borderRadius: '2px',
                                                            background: level <= strength
                                                                ? (strength <= 1 ? '#EF4444' : strength === 2 ? '#F59E0B' : strength === 3 ? '#3B82F6' : AppTheme.colors.successGreen)
                                                                : '#E5E7EB',
                                                            transition: 'background 0.3s'
                                                        }} />
                                                    );
                                                })}
                                            </div>
                                            <span style={{ fontSize: '12px', fontWeight: '600', color: AppTheme.colors.textTertiary }}>
                                                {formData.password.length < 6 ? 'Weak' : formData.password.length < 8 ? 'Fair' : formData.password.length < 12 ? 'Good' : 'Strong'}
                                            </span>
                                        </div>
                                    )}

                                    {/* Terms */}
                                    <p style={{ fontSize: '12px', color: AppTheme.colors.textTertiary, lineHeight: '1.5', textAlign: 'center', margin: '8px 0 0 0' }}>
                                        By creating an account, you agree to our{' '}
                                        <span style={{ color: AppTheme.colors.primaryPink, fontWeight: '600', cursor: 'pointer' }}>Terms of Service</span>
                                        {' '}and{' '}
                                        <span style={{ color: AppTheme.colors.primaryPink, fontWeight: '600', cursor: 'pointer' }}>Privacy Policy</span>
                                    </p>

                                    <div style={{ marginTop: 'auto', paddingTop: '16px' }}>
                                        <PremiumButton
                                            text="Create Account"
                                            type="gradient"
                                            fullWidth
                                            isLoading={isLoading}
                                            onClick={handleRegister}
                                            style={{ height: '56px', borderRadius: '16px', fontSize: '16px', fontWeight: '700' }}
                                        />
                                    </div>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </form>

                    <div style={{ textAlign: 'center', marginTop: '24px' }}>
                        <p style={{ color: AppTheme.colors.textSecondary, fontSize: '14px', fontWeight: '500' }}>
                            Already have an account?{' '}
                            <span
                                style={{ color: AppTheme.colors.primaryPink, cursor: 'pointer', fontWeight: '700', textDecoration: 'none' }}
                                onClick={() => navigate('/login')}
                            >
                                Log in
                            </span>
                        </p>
                    </div>
                </div>
            </motion.div>
        </div >
    );
};

export default Register;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FaChevronRight, FaBell, FaLock, FaUserShield, FaSignOutAlt, FaQuestionCircle, FaChevronLeft, FaRobot, FaHeart, FaCommentDots } from 'react-icons/fa';
import { AppTheme } from '../theme/AppTheme';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import { useToast } from '../context/ToastContext';

const Settings = () => {
    const { logout, user } = useAuth();
    const navigate = useNavigate();
    const { showToast } = useToast();
    const [activeSubView, setActiveSubView] = useState('main'); // 'main', 'notifications'

    const [notifSettings, setNotifSettings] = useState({
        newMatches: true,
        messages: true,
        likes: false,
        aiInsights: true,
        smartSuggestions: true
    });

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    const toggleNotif = (key) => {
        setNotifSettings(prev => ({ ...prev, [key]: !prev[key] }));
        showToast('Settings saved successfully', 'success');
    };

    const renderMainSettings = () => (
        <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.95 }}
            style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}
        >
            <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '16px' }}>
                <motion.button
                    whileTap={{ scale: 0.9 }}
                    onClick={() => navigate(-1)}
                    style={{ width: '40px', height: '40px', borderRadius: '50%', background: '#FFFFFF', boxShadow: '0 2px 10px rgba(0,0,0,0.05)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: AppTheme.colors.textPrimary, border: 'none', cursor: 'pointer' }}
                >
                    <FaChevronLeft size={16} />
                </motion.button>
                <h1 style={{ fontSize: '28px', fontWeight: '800', margin: 0, color: AppTheme.colors.textPrimary }}>Settings</h1>
            </div>

            {/* Profile Header Summary */}
            <section style={{ textAlign: 'center', marginBottom: '16px', background: '#FFFFFF', padding: '24px', borderRadius: '24px', boxShadow: '0 2px 10px rgba(0,0,0,0.02)' }}>
                <div style={{ position: 'relative', width: '90px', height: '90px', margin: '0 auto 16px' }}>
                    <img
                        src={user?.avatar || "https://images.unsplash.com/photo-1539571696357-5a69c17a67c6?w=400&h=400&fit=crop"}
                        alt="Profile"
                        style={{ width: '100%', height: '100%', borderRadius: '50%', objectFit: 'cover', border: `3px solid ${AppTheme.colors.primaryPink}` }}
                    />
                </div>
                <h2 style={{ fontSize: '22px', fontWeight: '800', margin: 0, color: AppTheme.colors.textPrimary }}>{user?.name || "Trish User"}</h2>
                <p style={{ color: AppTheme.colors.textSecondary, fontSize: '14px', marginTop: '4px' }}>Premium Member</p>
            </section>

            <SettingsGroup title="Account">
                <SettingsItem icon={FaBell} label="Notifications" onClick={() => setActiveSubView('notifications')} />
                <SettingsItem icon={FaLock} label="Privacy & Safety" />
                <SettingsItem icon={FaUserShield} label="Security" />
            </SettingsGroup>

            <SettingsGroup title="Support">
                <SettingsItem icon={FaQuestionCircle} label="Help Center" />
                <SettingsItem icon={FaQuestionCircle} label="Contact Us" />
            </SettingsGroup>

            <SettingsGroup title="Login">
                <motion.button
                    whileTap={{ scale: 0.98 }}
                    onClick={handleLogout}
                    style={{
                        width: '100%',
                        background: '#FEF2F2',
                        border: '1px solid #FECACA',
                        padding: '16px',
                        borderRadius: '16px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        gap: '12px',
                        color: '#EF4444',
                        fontSize: '16px',
                        fontWeight: '700',
                        cursor: 'pointer',
                        marginTop: '10px'
                    }}
                >
                    <FaSignOutAlt />
                    Log Out
                </motion.button>
            </SettingsGroup>

            <div style={{ textAlign: 'center', padding: '20px', color: AppTheme.colors.textTertiary }}>
                <div style={{ fontSize: '14px', fontWeight: '700', letterSpacing: '1px' }}>TRISH APP V1.0</div>
            </div>
        </motion.div>
    );

    const renderNotificationSettings = () => (
        <motion.div
            initial={{ opacity: 0, x: 50 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 50 }}
        >
            <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '32px' }}>
                <motion.button
                    whileTap={{ scale: 0.9 }}
                    onClick={() => setActiveSubView('main')}
                    style={{ width: '40px', height: '40px', borderRadius: '50%', background: '#FFFFFF', boxShadow: '0 2px 10px rgba(0,0,0,0.05)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: AppTheme.colors.textPrimary, border: 'none', cursor: 'pointer' }}
                >
                    <FaChevronLeft size={16} />
                </motion.button>
                <div>
                    <h2 style={{ margin: 0, fontSize: '24px', fontWeight: '800', color: AppTheme.colors.textPrimary }}>Notifications</h2>
                    <p style={{ margin: 0, fontSize: '14px', color: AppTheme.colors.textSecondary }}>Manage your alerts</p>
                </div>
            </div>

            <SettingsGroup title="Push Notifications">
                <ToggleItem
                    icon={FaHeart}
                    label="New Matches"
                    active={notifSettings.newMatches}
                    onToggle={() => toggleNotif('newMatches')}
                />
                <ToggleItem
                    icon={FaCommentDots}
                    label="Messages"
                    active={notifSettings.messages}
                    onToggle={() => toggleNotif('messages')}
                />
                <ToggleItem
                    icon={FaHeart}
                    label="Likes"
                    active={notifSettings.likes}
                    onToggle={() => toggleNotif('likes')}
                />
            </SettingsGroup>

            <SettingsGroup title="Smart Alerts">
                <ToggleItem
                    icon={FaRobot}
                    label="AI Match Insights"
                    active={notifSettings.aiInsights}
                    onToggle={() => toggleNotif('aiInsights')}
                />
                <ToggleItem
                    icon={FaRobot}
                    label="Conversation Starters"
                    active={notifSettings.smartSuggestions}
                    onToggle={() => toggleNotif('smartSuggestions')}
                />
            </SettingsGroup>
        </motion.div>
    );

    return (
        <div style={{
            minHeight: '100vh',
            background: AppTheme.colors.lightBackground,
            padding: '24px',
            paddingBottom: '120px',
            color: AppTheme.colors.textPrimary
        }}>
            <AnimatePresence mode="wait">
                {activeSubView === 'main' ? renderMainSettings() : renderNotificationSettings()}
            </AnimatePresence>
        </div>
    );
};

const SettingsGroup = ({ title, children }) => (
    <div style={{ marginBottom: '32px' }}>
        <h3 style={{ fontSize: '14px', textTransform: 'uppercase', letterSpacing: '1px', color: AppTheme.colors.textTertiary, marginBottom: '16px', paddingLeft: '8px', fontWeight: '700' }}>
            {title}
        </h3>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {children}
        </div>
    </div>
);

const SettingsItem = ({ icon: Icon, label, onClick }) => (
    <div onClick={onClick} style={{ padding: '16px', background: '#FFFFFF', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer', borderRadius: '16px', border: '1px solid #E5E7EB', boxShadow: '0 2px 5px rgba(0,0,0,0.02)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            <div style={{
                width: '40px', height: '40px', borderRadius: '12px',
                background: `${AppTheme.colors.primaryPink}15`, display: 'flex',
                alignItems: 'center', justifyContent: 'center', color: AppTheme.colors.primaryPink
            }}>
                <Icon size={18} />
            </div>
            <span style={{ fontWeight: '600', fontSize: '16px', color: AppTheme.colors.textPrimary }}>{label}</span>
        </div>
        <FaChevronRight size={14} color={AppTheme.colors.textTertiary} />
    </div>
);

const ToggleItem = ({ icon: Icon, label, active, onToggle }) => (
    <div style={{ padding: '16px', background: '#FFFFFF', display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderRadius: '16px', border: '1px solid #E5E7EB', boxShadow: '0 2px 5px rgba(0,0,0,0.02)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            <div style={{
                width: '40px', height: '40px', borderRadius: '12px',
                background: active ? `${AppTheme.colors.successGreen}15` : '#F3F4F6',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                color: active ? AppTheme.colors.successGreen : AppTheme.colors.textTertiary
            }}>
                <Icon size={18} />
            </div>
            <span style={{ fontWeight: '600', fontSize: '16px', color: AppTheme.colors.textPrimary }}>{label}</span>
        </div>
        <div
            onClick={onToggle}
            style={{
                width: '50px', height: '26px', borderRadius: '13px',
                background: active ? AppTheme.colors.successGreen : '#E5E7EB',
                position: 'relative', cursor: 'pointer', transition: 'all 0.3s'
            }}
        >
            <motion.div
                animate={{ x: active ? 26 : 4 }}
                style={{
                    width: '20px', height: '20px', borderRadius: '50%',
                    background: '#fff', position: 'absolute', top: '3px',
                    boxShadow: '0 2px 4px rgba(0,0,0,0.2)'
                }}
            />
        </div>
    </div>
);

export default Settings;

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { FaCrown, FaCheck, FaStar, FaBolt, FaArrowLeft } from 'react-icons/fa';
import GlassCard from '../components/common/GlassCard';
import PremiumButton from '../components/common/PremiumButton';
import { AppTheme } from '../theme/AppTheme';
import { useNavigate } from 'react-router-dom';
import { useToast } from '../context/ToastContext';

const PLANS = [
    {
        id: 'basic',
        name: 'Trish Plus',
        price: '₹599',
        period: '/mo',
        features: ['Unlimited Likes', 'See Who Liked You', '5 Super Likes/week', 'No Ads'],
        color: AppTheme.colors.brandBlue,
        icon: FaStar,
        gradient: 'linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)'
    },
    {
        id: 'premium',
        name: 'Trish Gold',
        price: '₹1499',
        period: '/mo',
        features: ['Everything in Plus', 'AI Personality Insights', 'Passport Global Access', '1 Boost/month', 'New Top Picks Every Day'],
        color: '#FBBF24',
        icon: FaCrown,
        popular: true,
        gradient: 'linear-gradient(135deg, #FBBF24 0%, #D97706 100%)'
    },
    {
        id: 'vip',
        name: 'Trish Platinum',
        price: '₹2999',
        period: '/mo',
        features: ['Everything in Gold', 'Priority Likes', 'Message Before Matching', 'Advanced Matching Filters', 'See Priority Matches'],
        color: '#1E293B',
        icon: FaBolt,
        gradient: 'linear-gradient(135deg, #1E293B 0%, #0F172A 100%)'
    }
];

export const subscriptionService = {
    subscribe: async (planId) => {
        return new Promise(resolve => {
            setTimeout(() => {
                resolve({ success: true, plan: planId });
            }, 1000);
        });
    }
};

const Subscription = () => {
    const navigate = useNavigate();
    const { showToast } = useToast();
    const [selectedPlan, setSelectedPlan] = useState('premium');
    const [isLoading, setIsLoading] = useState(false);

    const handleSubscribe = async () => {
        setIsLoading(true);
        const result = await subscriptionService.subscribe(selectedPlan);
        setIsLoading(false);
        if (result.success) {
            showToast("Subscription Successful! Enjoy your premium benefits.", "success");
            navigate('/profile');
        }
    };

    return (
        <div style={{
            minHeight: '100vh',
            background: AppTheme.colors.lightBackground,
            padding: '24px',
            color: AppTheme.colors.textPrimary,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center'
        }}>
            <div style={{ width: '100%', maxWidth: '800px', marginBottom: '20px' }}>
                <motion.button
                    whileTap={{ scale: 0.9 }}
                    onClick={() => navigate(-1)}
                    style={{ background: '#FFFFFF', border: 'none', color: AppTheme.colors.textPrimary, cursor: 'pointer', padding: '12px', borderRadius: '50%', boxShadow: '0 2px 5px rgba(0,0,0,0.05)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                >
                    <FaArrowLeft size={16} />
                </motion.button>
            </div>

            <div style={{ textAlign: 'center', marginBottom: '40px' }}>
                <FaCrown size={48} color="#FBBF24" style={{ marginBottom: '16px' }} />
                <h1 style={{ fontSize: '32px', marginBottom: '8px', fontWeight: '800', color: AppTheme.colors.textPrimary }}>Unlock Trish Premium</h1>
                <p style={{ color: AppTheme.colors.textSecondary, fontSize: '16px' }}>Elevate your dating experience</p>
            </div>

            <div style={{
                display: 'flex',
                flexDirection: 'column',
                gap: '24px',
                width: '100%',
                maxWidth: '600px',
                marginBottom: '100px'
            }}>
                {PLANS.map((plan) => {
                    const isSelected = selectedPlan === plan.id;
                    return (
                        <motion.div
                            key={plan.id}
                            whileHover={{ scale: 1.02, y: -5 }}
                            onClick={() => setSelectedPlan(plan.id)}
                            style={{ cursor: 'pointer', position: 'relative' }}
                        >
                            {plan.popular && (
                                <div style={{
                                    position: 'absolute',
                                    top: '-12px',
                                    left: '50%',
                                    transform: 'translateX(-50%)',
                                    background: AppTheme.gradients.primary,
                                    color: '#FFFFFF',
                                    padding: '6px 16px',
                                    borderRadius: '16px',
                                    fontSize: '12px',
                                    fontWeight: '800',
                                    zIndex: 10,
                                    boxShadow: '0 4px 10px rgba(253, 41, 123, 0.3)'
                                }}>
                                    MOST POPULAR
                                </div>
                            )}
                            <div style={{
                                padding: '24px',
                                borderRadius: '24px',
                                border: isSelected ? 'none' : '1px solid #E5E7EB',
                                background: isSelected ? plan.gradient : '#FFFFFF',
                                color: isSelected ? '#FFFFFF' : AppTheme.colors.textPrimary,
                                boxShadow: isSelected ? `0 20px 40px ${plan.id === 'vip' ? 'rgba(30, 41, 59, 0.4)' : 'rgba(251, 191, 36, 0.4)'}` : '0 4px 15px rgba(0,0,0,0.02)',
                                transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                                position: 'relative',
                                overflow: 'hidden'
                            }}>
                                {isSelected && (
                                    <motion.div
                                        initial={{ x: '-100%' }}
                                        animate={{ x: '100%' }}
                                        transition={{ duration: 1.5, repeat: Infinity, ease: "linear" }}
                                        style={{
                                            position: 'absolute', inset: 0,
                                            background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent)',
                                            zIndex: 1
                                        }}
                                    />
                                )}
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '20px', position: 'relative', zIndex: 2 }}>
                                    <div>
                                        <h3 style={{ fontSize: '22px', fontWeight: '800', color: isSelected ? '#FFFFFF' : plan.color, marginBottom: '4px' }}>{plan.name}</h3>
                                        <div style={{ display: 'flex', alignItems: 'baseline', gap: '4px' }}>
                                            <span style={{ fontSize: '32px', fontWeight: '900' }}>{plan.price}</span>
                                            <span style={{ fontSize: '15px', opacity: 0.8, fontWeight: '500' }}>{plan.period}</span>
                                        </div>
                                    </div>
                                    <div style={{ width: '50px', height: '50px', borderRadius: '16px', background: isSelected ? 'rgba(255,255,255,0.2)' : `${plan.color}15`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <plan.icon size={24} color={isSelected ? '#FFFFFF' : plan.color} />
                                    </div>
                                </div>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', position: 'relative', zIndex: 2 }}>
                                    {plan.features.map((feature, i) => (
                                        <div key={i} style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                                            <div style={{ width: '20px', height: '20px', borderRadius: '50%', background: isSelected ? 'rgba(255,255,255,0.2)' : `${AppTheme.colors.successGreen}20`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                                <FaCheck size={10} color={isSelected ? '#FFFFFF' : AppTheme.colors.successGreen} />
                                            </div>
                                            <span style={{ fontSize: '15px', color: isSelected ? 'rgba(255,255,255,0.9)' : AppTheme.colors.textSecondary, fontWeight: '500' }}>{feature}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </motion.div>
                    );
                })}
            </div>

            <div style={{
                position: 'fixed',
                bottom: 0,
                left: 0,
                right: 0,
                padding: '24px',
                background: 'rgba(255, 255, 255, 0.95)',
                backdropFilter: 'blur(10px)',
                borderTop: '1px solid #E5E7EB',
                display: 'flex',
                justifyContent: 'center',
                boxShadow: '0 -4px 20px rgba(0,0,0,0.05)',
                zIndex: 100
            }}>
                <div style={{ width: '100%', maxWidth: '400px' }}>
                    <PremiumButton
                        text={`Subscribe to ${PLANS.find(p => p.id === selectedPlan).name}`}
                        type="gradient"
                        fullWidth
                        isLoading={isLoading}
                        onClick={handleSubscribe}
                    />
                </div>
            </div>
        </div>
    );
};

export default Subscription;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FaPhoneSlash, FaMicrophone, FaMicrophoneSlash, FaVideo, FaVideoSlash, FaShieldAlt, FaEllipsisV } from 'react-icons/fa';
import { useNavigate, useLocation } from 'react-router-dom';
import { AppTheme } from '../theme/AppTheme';

const VideoCall = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const { matchName, matchImage } = location.state || { matchName: "Sarah", matchImage: "https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=600" };

    const [aiInsight, setAiInsight] = useState("Initializing AI Security Shield...");
    const [sparkLevel, setSparkLevel] = useState(0);
    const [isConnecting, setIsConnecting] = useState(true);
    const [callDuration, setCallDuration] = useState(0);
    const [isMuted, setIsMuted] = useState(false);
    const [isVideoOff, setIsVideoOff] = useState(false);

    const insights = [
        "Positive sentiment detected. You're both smiling!",
        "Mutual interests found: 'Adventure' & 'Coffee'.",
        "TRISH AI Suggestion: Ask about her recent trip!",
        "Match Compatibility: 94% and rising.",
        "Emotional Resonance: High Sync detected."
    ];

    useEffect(() => {
        const timer = setTimeout(() => setIsConnecting(false), 2500);
        return () => clearTimeout(timer);
    }, []);

    useEffect(() => {
        if (isConnecting) return;
        const interval = setInterval(() => setCallDuration((prev) => prev + 1), 1000);
        return () => clearInterval(interval);
    }, [isConnecting]);

    useEffect(() => {
        if (!isConnecting) {
            const insightInterval = setInterval(() => {
                setAiInsight(insights[Math.floor(Math.random() * insights.length)]);
                setSparkLevel(prev => Math.min(100, prev + Math.floor(Math.random() * 15)));
            }, 6000);
            return () => clearInterval(insightInterval);
        }
    }, [isConnecting]);

    const formatTime = (seconds) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    const handleEndCall = () => {
        navigate(-1);
    };

    return (
        <div style={{
            height: '100vh',
            width: '100vw',
            background: '#0F172A',
            position: 'fixed',
            inset: 0,
            zIndex: 9999,
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
            fontFamily: 'Inter, sans-serif'
        }}>
            {/* Main Remote Video View */}
            <div style={{ flex: 1, position: 'relative' }}>
                <AnimatePresence>
                    {isConnecting ? (
                        <motion.div
                            key="connecting"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            style={{
                                position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column',
                                alignItems: 'center', justifyContent: 'center',
                                background: 'radial-gradient(circle at center, #1e1b4b 0%, #0f172a 100%)',
                                zIndex: 10
                            }}
                        >
                            <div style={{ position: 'relative' }}>
                                <motion.div
                                    animate={{
                                        scale: [1, 1.2, 1],
                                        boxShadow: [
                                            '0 0 20px rgba(253, 41, 123, 0.2)',
                                            '0 0 40px rgba(253, 41, 123, 0.5)',
                                            '0 0 20px rgba(253, 41, 123, 0.2)'
                                        ]
                                    }}
                                    transition={{ repeat: Infinity, duration: 3 }}
                                    style={{ width: '140px', height: '140px', borderRadius: '50%', overflow: 'hidden', marginBottom: '32px', border: '5px solid #FFFFFF' }}
                                >
                                    <img src={matchImage} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover', filter: 'grayscale(30%)' }} />
                                </motion.div>
                                <motion.div
                                    animate={{ rotate: 360 }}
                                    transition={{ repeat: Infinity, duration: 8, ease: 'linear' }}
                                    style={{ position: 'absolute', inset: '-15px', border: '2px dashed rgba(253, 41, 123, 0.4)', borderRadius: '50%' }}
                                />
                            </div>
                            <h2 style={{ color: '#fff', fontSize: '28px', fontWeight: '900', marginBottom: '8px', letterSpacing: '-0.5px' }}>Calling {matchName}</h2>
                            <motion.p
                                animate={{ opacity: [0.4, 1, 0.4] }}
                                transition={{ repeat: Infinity, duration: 2 }}
                                style={{ color: '#94A3B8', fontSize: '15px', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '8px' }}
                            >
                                <FaShieldAlt color="#FDA4AF" /> Establishing Neural Link...
                            </motion.p>
                        </motion.div>
                    ) : (
                        <motion.div
                            key="call"
                            initial={{ opacity: 0, scale: 1.1 }}
                            animate={{ opacity: 1, scale: 1 }}
                            style={{ position: 'absolute', inset: 0 }}
                        >
                            <img src={matchImage} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                            <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 30%, transparent 70%, rgba(0,0,0,0.5) 100%)' }} />

                            {/* AI Neural HUD */}
                            <motion.div
                                initial={{ opacity: 0, x: -20 }}
                                animate={{ opacity: 1, x: 0 }}
                                style={{
                                    position: 'absolute', left: '24px', bottom: '160px',
                                    maxWidth: '280px', zIndex: 110
                                }}
                            >
                                <div style={{
                                    padding: '16px 20px', background: 'rgba(30, 27, 75, 0.6)',
                                    backdropFilter: 'blur(20px)', borderRadius: '24px',
                                    border: '1px solid rgba(255,255,255,0.15)',
                                    boxShadow: '0 10px 30px rgba(0,0,0,0.3)'
                                }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                                        <FaMagic color="#FBBF24" size={14} />
                                        <span style={{ fontSize: '12px', fontWeight: '900', color: '#FBBF24', textTransform: 'uppercase', letterSpacing: '1px' }}>AI Insight</span>
                                    </div>
                                    <p style={{ margin: 0, color: '#fff', fontSize: '14px', fontWeight: '600', lineHeight: '1.4' }}>
                                        {aiInsight}
                                    </p>
                                </div>
