            const response = await api.get('/matches');
            return response.data;
        } catch (error) {
            console.warn("Using mock matches");
            return MOCK_MATCHES;
        }
    },

    getMatchDetails: async (matchId) => {
        try {
            const response = await api.get(`/matches/${matchId}`);
            return response.data;
        } catch (error) {
            return MOCK_MATCHES.find(m => m.id === parseInt(matchId));
        }
    },

    unmatch: async (matchId) => {
        try {
            await api.delete(`/matches/${matchId}`);
            return { success: true };
        } catch (error) {
            return { success: true };
        }
    },

    updateRevealProgress: async (matchId, progress) => {
        try {
            const response = await api.post(`/matches/${matchId}/reveal`, { progress });
            return response.data;
        } catch (error) {
            console.error("Failed to update reveal progress:", error);
            return null;
        }
    }
};

