export const userService = {
    getProfile: async () => {
        try {
            const response = await api.get('/users/profile');
            return response.data;
        } catch (error) {
            console.warn("Using mock profile");
            return JSON.parse(localStorage.getItem('user'));
        }
    },

    updateProfile: async (data) => {
        try {
            const response = await api.put('/users/profile', data);
            return response.data;
        } catch (error) {
            console.warn("Using mock profile update");
            const user = { ...JSON.parse(localStorage.getItem('user')), ...data };
            localStorage.setItem('user', JSON.stringify(user));
            return user;
        }
    },

    getRecommendations: async () => {
        try {
            const response = await api.get('/recommendations');
            return response.data;
        } catch (error) {
            console.warn("Using mock recommendations");
            return MOCK_RECOMMENDATIONS;
        }
    },

    swipe: async (targetUserId, action, isBlindDate = false) => {
        try {
            // Map action to enum SwipeType: LIKE, PASS, SUPER_LIKE
            const typeMap = {
                'like': 'LIKE',
                'pass': 'PASS',
                'superlike': 'SUPER_LIKE',
                'super': 'SUPER_LIKE'
            };
            const type = typeMap[action] || 'LIKE';
            const response = await api.post('/swipes', { targetUserId, type, blindDate: isBlindDate });
            return response.data;
        } catch (error) {
            console.warn(`Using mock swipe: ${action} on ${targetUserId}`);
            return { success: true, matched: action === 'like' && Math.random() > 0.5 };
        }
    },

    // Premium Features
    activateBoost: async (userId) => {
        try {
            const response = await api.post(`/premium/boost?userId=${userId}`);
            return response.data;
        } catch (error) {
            console.warn("Using mock boost activation");
            return { isBoosted: true, boostExpiresAt: new Date(Date.now() + 30 * 60000) };
        }
    },

    setPassport: async (userId, locationData) => {
        try {
            const response = await api.post(`/premium/passport?userId=${userId}`, locationData);
            return response.data;
        } catch (error) {
            console.warn("Using mock passport activation");
            return { isPassportActive: true, passportCity: locationData.city };
        }
    },

    deactivatePassport: async (userId) => {
        try {
            const response = await api.delete(`/premium/passport?userId=${userId}`);
            return response.data;
        } catch (error) {
            console.warn("Using mock passport deactivation");
            return { isPassportActive: false };
        }
    }
};

